// Unit 11: Auf dem Weihnachtsmarkt
// Level: A2

const UNIT_11 =
{n:11,lang:"de",srcLang:"en",track:"v2",title:"Auf dem Weihnachtsmarkt",sub:"Christmas market, Opa Heinrich, Glühwein, adjective declension",icon:"🎄",level:"A2.3",color:"#7B5EE8",lessons:[
{id:"deu_r11l1",title:"Gendarmenmarkt",icon:"🎄",xp:15,board:true,steps:[
{type:"intro",title:"Gendarmenmarkt",desc:"Dusk falls over Berlin's most beautiful Christmas market. Golden lights, wooden stalls, the smell of Glühwein and roasted almonds. Hildi pulls Verumius into the crowd.",goals:["Learn 10 winter and Christmas market words","See adjective endings in real sentences","Discover German Weihnachtsmarkt culture"]},

{type:"story",speaker:"narrator",mood:"enchanted",art:"de-ber-gendarmenmarkt-dusk",trg:"Berlin, Dezember. Die Sonne ist seit einer Stunde weg. Aber der Gendarmenmarkt leuchtet. Goldene Lichter an jeder Holzbude, Dampf über den Ständen, der Geruch von gebrannten Mandeln in der kalten Luft.",src:"Berlin, December. The sun has been gone for an hour. But the Gendarmenmarkt glows. Golden lights on every wooden stall, steam over the stands, the smell of roasted almonds in the cold air."},
{type:"story",speaker:"hildi",mood:"proud",art:"de-ber-gendarmenmarkt-entrance",trg:"Das ist er. Der schönste Weihnachtsmarkt in ganz Berlin. Ich komme seit dreißig Jahren hierher.",src:"This is it. The most beautiful Christmas market in all of Berlin. I have been coming here for thirty years."},
{type:"story",speaker:"verumius",mood:"overwhelmed",art:"de-ber-gendarmenmarkt-lights",trg:"So viele Lichter. So viele Menschen. Und dieser Geruch. Was ist das?",src:"So many lights. So many people. And that smell. What is that?"},
{type:"teach",trg:"das Weihnachten",
  pos:"noun",src:"Christmas",phonetic:"VYE-nakh-ten",gender:"n",example:"A: Was machst du an Weihnachten?\nB: Ich besuche meine Familie.\nA: Das klingt schön!",exampleSrc:"A: What are you doing at Christmas?\nB: I am visiting my family.\nA: That sounds lovely!",note:"das Weihnachten (neuter). Often used without article: 'an Weihnachten' or 'zu Weihnachten.' Compound: Weih (holy) + Nachten (nights).",funFact:"Germany celebrates on Heiligabend (Christmas Eve, Dec 24), not Dec 25. Gifts are opened in the evening, often after church. The 25th and 26th are quiet family days."},
{type:"teach",trg:"der Schnee",
  pos:"noun",src:"the snow",phonetic:"shnay",gender:"m",example:"A: Schau mal, der Schnee!\nB: Ja, alles ist weiß. Wie im Märchen!",exampleSrc:"A: Look, the snow!\nB: Yes, everything is white. Like in a fairy tale!",note:"der Schnee (masculine, no plural). Related: schneien (to snow), Schneemann (snowman).",funFact:"Germans have a saying: 'Weiße Weihnachten' (white Christmas). Statistically, Berlin gets snow on Christmas Day only about once every 10 years."},
{type:"teach",trg:"schneien",
  pos:"verb",
  gender:null,src:"to snow",example:"A: Es schneit! Hast du einen Schirm?\nB: Nein, aber ich habe eine Mütze.",exampleSrc:"A: It's snowing! Do you have an umbrella?\nB: No, but I have a hat.",note:"Impersonal verb: always 'es schneit' (it snows). Past: es hat geschneit.",funFact:"The word 'schneien' comes from Old High German 'snīwan'. In Bavaria, heavy snow is called 'Schneegestöber' (snow flurry)."},
{type:"teach",trg:"die Wolke",
  pos:"noun",src:"the cloud",gender:"f",example:"A: Siehst du die dunklen Wolken?\nB: Ja, es schneit bestimmt bald.",exampleSrc:"A: Do you see the dark clouds?\nB: Yes, it will definitely snow soon.",note:"die Wolke, plural: die Wolken. 'Wolkenkratzer' means skyscraper (cloud scratcher).",funFact:"The German word 'Wolkenkuckucksheim' (cloud cuckoo land) means a fantasy world. It comes from an ancient Greek comedy by Aristophanes."},
{type:"teach",trg:"der Himmel",
  pos:"noun",src:"the sky / heaven",gender:"m",example:"A: Der Himmel ist so schön heute Abend.\nB: Ja, die Sterne leuchten über dem Markt.",exampleSrc:"A: The sky is so beautiful this evening.\nB: Yes, the stars shine above the market.",note:"der Himmel = sky AND heaven. 'Himmelblau' = sky blue. Plural: die Himmel (rare).",funFact:"'Himmel und Hölle' (heaven and hell) is the German name for hopscotch. Kids still play it in schoolyards across Germany."},
{type:"teach",trg:"der Kalender",
  pos:"noun",src:"the calendar",gender:"m",example:"A: Hast du einen Adventskalender?\nB: Ja, mit Schokolade! Heute ist Türchen Nummer zwölf.",exampleSrc:"A: Do you have an Advent calendar?\nB: Yes, with chocolate! Today is door number twelve.",note:"der Kalender, plural: die Kalender. Adventskalender = Advent calendar (24 little doors, one per day until Christmas).",funFact:"The first printed Advent calendar was made in Germany in 1902. Today, Germans spend over 60 million euros on them every year."},
{type:"teach",trg:"die Postkarte",
  pos:"noun",src:"the postcard",gender:"f",example:"A: Ich schreibe eine Postkarte an meine Eltern.\nB: Gute Idee! Der Weihnachtsmarkt ist ein tolles Motiv.",exampleSrc:"A: I'm writing a postcard to my parents.\nB: Good idea! The Christmas market is a great motif.",note:"die Postkarte, plural: die Postkarten. Compound: Post (mail) + Karte (card).",funFact:"Germany's postal service delivers around 200 million Christmas cards every December. The town of 'Himmelpfort' (Heaven's Gate) has a special Santa Claus post office."},
{type:"mc",q:"Hildi says: 'Schau, es ___!' What is happening?",opts:["Es regnet","Es schneit","Es ist warm","Es ist dunkel"],ans:"Es schneit",hint:"Think of what falls from winter clouds"},
{type:"fb",s:"Der {1} ist heute Abend wunderschön.",a:"Himmel",opts:["Himmel","Schnee","Wolke","Kalender"],hint:"Look up above the market stalls",sSrc:"The sky is beautiful tonight."},
{type:"teach",trg:"die Schokolade",
  pos:"noun",src:"the chocolate",gender:"f",example:"A: Möchtest du heiße Schokolade?\nB: Oh ja, bitte! Mit Sahne?",exampleSrc:"A: Would you like hot chocolate?\nB: Oh yes, please! With cream?",note:"die Schokolade (no common plural). Heiße Schokolade = hot chocolate. Short form: Schoki.",funFact:"Germany is the largest chocolate consumer in Europe, averaging 11 kg per person per year. Ritter Sport and Milka are iconic German brands."},
{type:"teach",trg:"die Torte",
  pos:"noun",src:"the cake / tart",gender:"f",example:"A: Diese Torte sieht lecker aus!\nB: Das ist Schwarzwälder Kirschtorte. Sehr berühmt!",exampleSrc:"A: This cake looks delicious!\nB: That is Black Forest cherry cake. Very famous!",note:"die Torte, plural: die Torten. Different from 'der Kuchen' (simpler cake). Torte = layered, fancy.",funFact:"Schwarzwälder Kirschtorte (Black Forest cake) must legally contain Kirschwasser (cherry brandy) to carry the name. It was invented around 1915."},
{type:"teach",trg:"die Rose",
  pos:"noun",src:"the rose",gender:"f",example:"A: Rosen im Winter?\nB: Ja, rote Rosen für den Weihnachtstisch!",exampleSrc:"A: Roses in winter?\nB: Yes, red roses for the Christmas table!",note:"die Rose, plural: die Rosen. Same word as English, from Latin 'rosa'.",funFact:"Germany grows over 80 million roses per year, mostly in greenhouses. The city of Bad Langensalza is called the 'Rosenstadt' (Rose City)."},
{type:"teach",trg:"der Ring",
  pos:"noun",src:"the ring",gender:"m",example:"A: Schau mal, der goldene Ring am Stand!\nB: Sehr schön. Ist das ein Geschenk?",exampleSrc:"A: Look, the golden ring at the stall!\nB: Very nice. Is that a gift?",note:"der Ring, plural: die Ringe. Also means circle or arena (Boxring).",funFact:"The 'Ringstraße' tradition in German cities dates back to medieval times, when ring roads replaced old city walls. Vienna's famous Ringstraße is the most well known."},
{type:"tip",title:"Weihnachtsmarkt: A German Tradition",text:"Christmas markets (Weihnachtsmärkte) open across Germany from late November until Christmas Eve. Every city has its own.\n\nBerlin alone has over 60 markets. The Gendarmenmarkt is considered the most beautiful, framed by two cathedrals and the Konzerthaus.\n\nTypical treats: Glühwein (mulled wine), gebrannte Mandeln (roasted almonds), Lebkuchen (gingerbread), Bratwurst, Stollen (fruit bread).\n\nThe tradition dates back to the 1300s. Dresden's Striezelmarkt (founded 1434) is the oldest.",deepDive:"Markets are called 'Weihnachtsmarkt' or 'Christkindlmarkt' (especially in southern Germany). Each region has specialties: Nuremberg is famous for its tiny Lebkuchen, Aachen for Printen cookies, and Dresden for Christstollen."},
{type:"mc",q:"What is 'die Schokolade'?",opts:["calendar","postcard","chocolate","sweet cake"],ans:"chocolate",hint:"A sweet treat, often served hot in winter"},
{type:"mc",q:"Verumius wants to write home. Which does he need?",opts:["der Kalender","die Torte","die Postkarte","ein goldener Ring"],ans:"die Postkarte",hint:"Something you write on and send by mail"},
{type:"fb",s:"Es gibt dunkle {1} am Himmel.",a:"Wolken",opts:["Wolken","Schnee","Ringe","Rosen"],hint:"These float in the sky before snow falls",sSrc:"There are dark clouds in the sky."},
{type:"mc",q:"'Die Torte' is different from 'der Kuchen' because a Torte is...",opts:["layered and fancy","simple and plain","always chocolate","served at room temperature"],ans:"layered and fancy",hint:"Think of a decorated multi-layer dessert"},
{type:"fb",s:"Hildi kauft eine {1} am Weihnachtsmarkt.",a:"Rose",opts:["Rose","Wolke","Schnee","Himmel"],hint:"A beautiful flower, often red",sSrc:"Hildi buys a rose at the Christmas market."},
{type:"mc",q:"Verumius sees a round golden item on a stall. Which word describes it?",opts:["die Rose","der Schnee","der Ring","die Torte"],ans:"der Ring",hint:"A small circular object worn as jewellery on a finger."},
{type:"match",pairs:[{trg:"der Schnee",src:"the snow"},{trg:"die Wolke",src:"the cloud"},{trg:"der Himmel",src:"the sky"},{trg:"die Postkarte",src:"the postcard"},{trg:"die Schokolade",src:"the chocolate"},{trg:"die Rose",src:"the rose"}]},

{type:"tip",title:"Sneak Peek: Adjective Endings",text:"You saw phrases like 'der warme Glühwein', 'die dunklen Wolken', 'der goldene Ring'.\n\nNotice the endings on the adjectives: warm-E, dunkel-N, golden-E.\n\nGerman adjectives change their endings depending on gender, case, and article. This is called adjective declension.\n\nDo not memorize rules yet. Just notice the patterns. You will learn the system step by step in coming lessons.",deepDive:"Adjective declension is one of German's trickiest grammar topics. There are three declension patterns (strong, weak, mixed) depending on what comes before the adjective. For now, just get used to hearing 'der warme', 'die schöne', 'das frische' as natural chunks."},
{type:"mc",q:"Hildi sagt: 'Der Gendarmenmarkt hat den schönsten Weihnachtsmarkt in Berlin.' What does she mean?",opts:["Gendarmenmarkt has the most beautiful Christmas market in Berlin","Gendarmenmarkt has the biggest Christmas market in Berlin","Gendarmenmarkt has the most historic and oldest Christmas market in Berlin","Gendarmenmarkt has the cheapest Christmas market in Berlin"],ans:"Gendarmenmarkt has the most beautiful Christmas market in Berlin",hint:"'schön' is an adjective in its highest form (superlative) here."},
{type:"story",speaker:"verumius",mood:"curious-warm",art:"de-ber-gendarmenmarkt-crowd",trg:"Hildi? Danke, dass du mich mitgenommen hast. Ich habe so etwas noch nie gesehen.",src:"Hildi? Thank you for bringing me along. I have never seen anything like this."},
{type:"story",speaker:"hildi",mood:"gentle",art:"de-ber-gendarmenmarkt-snow",trg:"Der Abend hat gerade erst angefangen, mein Junge. Wir warten noch auf jemanden.",src:"The evening has only just begun, my boy. We are still waiting for someone."}
]},

{id:"deu_r11l2",title:"Was ziehe ich an?",icon:"🧣",xp:15,board:true,steps:[
{type:"intro",title:"Was ziehe ich an?",desc:"It's cold at the Christmas market! Learn the most important clothing items for winter.",goals:["14 clothing words with their articles","Talk about clothing","Dress for cold weather"]},

{type:"story",speaker:"narrator",mood:"playful",art:"de-ber-gendarmenmarkt-cold",trg:"Es ist minus drei Grad. Verumius trägt eine dünne Jacke und keine Mütze. Hildi sieht ihn an. Langsam. Von oben nach unten.",src:"It is minus three degrees. Verumius is wearing a thin jacket and no hat. Hildi looks at him. Slowly. From top to bottom."},
{type:"story",speaker:"hildi",mood:"disapproving",art:"de-ber-clothing-lecture",trg:"Nein. Nein, nein, nein. So gehst du nicht auf den Weihnachtsmarkt. Wo ist dein Schal? Wo ist deine Mütze?",src:"No. No, no, no. You are not going to the Christmas market like this. Where is your scarf? Where is your hat?"},
{type:"teach",trg:"der Mantel",
  pos:"noun",src:"the coat",gender:"m",phonetic:"MAN-tel",example:"A: Es ist so kalt draußen!\nB: Zieh deinen Mantel an!",exampleSrc:"A: It's so cold outside!\nB: Put your coat on!",note:"der Mantel, masculine. Plural: die Mäntel.",funFact:"German Christmas markets run from late November to December 23rd, so a warm Mantel is essential."},
{type:"teach",trg:"die Mütze",
  pos:"noun",src:"the hat/beanie",gender:"f",phonetic:"MÜT-tse",example:"A: Hast du eine Mütze?\nB: Ja, ich trage immer meine rote Mütze.",exampleSrc:"A: Do you have a beanie?\nB: Yes, I always wear my red beanie.",note:"die Mütze, feminine. For formal hats, use der Hut.",funFact:"In Bavaria, the traditional Filzhut (felt hat) is still worn at festivals, but a Mütze keeps your ears warm."},
{type:"teach",trg:"der Stiefel",
  pos:"noun",src:"the boot",gender:"m",phonetic:"SHTEE-fel",example:"A: Welche Schuhe trägst du heute?\nB: Meine schwarzen Stiefel, es schneit!",exampleSrc:"A: Which shoes are you wearing today?\nB: My black boots, it's snowing!",note:"der Stiefel, masculine. Plural: die Stiefel (same form).",funFact:"The word Stiefel also means a large beer glass shaped like a boot, popular at Oktoberfest."},
{type:"teach",trg:"der Pullover",
  pos:"noun",src:"the sweater",gender:"m",phonetic:"pul-OH-ver",example:"A: Der Pullover sieht warm aus.\nB: Ja, er ist aus Wolle.",exampleSrc:"A: That sweater looks warm.\nB: Yes, it's made of wool.",note:"der Pullover, masculine. Often shortened to Pulli in everyday speech.",funFact:"Pullover comes from English 'pull over'. Germans borrowed the word but gave it a masculine article."},
{type:"teach",trg:"die Hose",
  pos:"noun",src:"the pants",gender:"f",phonetic:"HO-ze",example:"A: Die Hose passt dir gut!\nB: Danke, sie ist neu.",exampleSrc:"A: The pants fit you well!\nB: Thanks, they're new.",note:"die Hose, feminine. Always singular in German, unlike English 'pants'.",funFact:"Lederhosen literally means 'leather pants'. die Hose is singular even though pants come in pairs."},
{type:"teach",trg:"das Hemd",
  pos:"noun",src:"the shirt",gender:"n",phonetic:"HEMT",example:"A: Trägst du ein Hemd zur Arbeit?\nB: Ja, ein weißes Hemd.",exampleSrc:"A: Do you wear a shirt to work?\nB: Yes, a white shirt.",note:"das Hemd, neuter. Refers to a button-up shirt specifically.",funFact:"Das Hemd is related to the old German word for 'cover'. A T-Shirt is a separate word in German."},
{type:"teach",trg:"das Kleid",
  pos:"noun",src:"the dress",gender:"n",phonetic:"KLITE",example:"A: Das Kleid ist wunderschön!\nB: Danke, ich trage es gern.",exampleSrc:"A: The dress is beautiful!\nB: Thanks, I like wearing it.",note:"das Kleid, neuter. Plural: die Kleider. Also means 'clothes' in plural.",funFact:"Kleider machen Leute is a famous German proverb: 'Clothes make the person.'"},
{type:"mc",q:"Wie sagt man 'coat' auf Deutsch?",opts:["die Mütze","der Pullover","das Hemd","der Mantel"],ans:"der Mantel",hint:"Think of something long that keeps you warm outside."},
{type:"fb",s:"Im Winter trage ich immer meine {1}.",a:"Mütze",opts:["Mütze","Mantel","Hemd","Kleid"],hint:"It keeps your ears warm on cold days.",sSrc:"In winter I always wear my beanie."},
{type:"teach",trg:"die Bluse",
  pos:"noun",src:"the blouse",gender:"f",phonetic:"BLUE-ze",example:"A: Die Bluse passt gut zum Rock.\nB: Findest du? Ich bin nicht sicher.",exampleSrc:"A: The blouse goes well with the skirt.\nB: You think so? I'm not sure.",note:"die Bluse, feminine. Similar to Hemd but typically for women.",funFact:"German fashion vocabulary often borrows from French. Bluse came via French from medieval Latin."},
{type:"teach",trg:"der Rock",
  pos:"noun",src:"the skirt",gender:"m",phonetic:"ROK",example:"A: Der Rock ist zu kurz für den Winter.\nB: Dann ziehe ich eine Hose an.",exampleSrc:"A: The skirt is too short for winter.\nB: Then I'll put on pants.",note:"der Rock, masculine. Be careful: Rock also means 'rock music' in German.",funFact:"Der Rock is masculine even though it refers to a garment traditionally worn by women. German grammar does not follow logic."},
{type:"teach",trg:"die Jeans",
  pos:"noun",src:"the jeans",gender:"f",phonetic:"JEENS",example:"A: Ich trage am liebsten Jeans.\nB: Ich auch, sie sind so bequem!",exampleSrc:"A: I prefer wearing jeans.\nB: Me too, they're so comfortable!",note:"die Jeans, feminine. Pronounced like in English. Singular in German.",funFact:"Jeans were invented by Levi Strauss, a German immigrant from Bavaria who moved to San Francisco."},
{type:"teach",trg:"der Schirm",
  pos:"noun",src:"the umbrella",gender:"m",phonetic:"SHIRM",example:"A: Hast du einen Schirm dabei?\nB: Nein, aber es regnet!",exampleSrc:"A: Do you have an umbrella with you?\nB: No, but it's raining!",note:"der Schirm, masculine. Short for der Regenschirm (rain umbrella).",funFact:"Schirm literally means 'shield'. A Bildschirm is a 'picture shield', the German word for screen or monitor."},
{type:"teach",trg:"der Anzug",
  pos:"noun",src:"the suit",gender:"m",phonetic:"AN-tsook",example:"A: Wann trägst du einen Anzug?\nB: Nur bei der Arbeit.",exampleSrc:"A: When do you wear a suit?\nB: Only at work.",note:"der Anzug, masculine. Literally 'something you pull on' (anziehen).",funFact:"Anzug comes from anziehen (to put on). German builds many clothing words from the verb 'to dress'."},
{type:"teach",trg:"die Brille",
  pos:"noun",src:"the glasses",gender:"f",phonetic:"BRIL-le",example:"A: Ohne meine Brille sehe ich nichts.\nB: Dann vergiss sie nicht!",exampleSrc:"A: Without my glasses I can't see anything.\nB: Then don't forget them!",note:"die Brille, feminine. Always singular in German, even though you wear two lenses.",funFact:"Brille comes from Beryll, a gemstone once used to make lenses in the Middle Ages."},
{type:"teach",trg:"das T-Shirt",
  pos:"noun",src:"the t-shirt",gender:"n",phonetic:"TEE-shört",example:"A: Im Sommer trage ich nur ein T-Shirt.\nB: Im Winter brauchst du mehr!",exampleSrc:"A: In summer I only wear a t-shirt.\nB: In winter you need more!",note:"das T-Shirt, neuter. Borrowed from English. Always capitalized in German.",funFact:"German capitalizes all nouns, so even borrowed words like T-Shirt get a capital letter and an article."},
{type:"tip",title:"Sich anziehen: Dressing for the Weihnachtsmarkt",text:"Germans layer up for winter markets:\n\n1. das Unterhemd (undershirt)\n2. das Hemd oder der Pullover\n3. der Mantel\n4. die Mütze, der Schal, die Handschuhe\n\nUseful verb: anziehen (to put on)\nIch ziehe meinen Mantel an.\nZieh dich warm an! (Dress warmly!)",deepDive:"anziehen is a separable verb: the an- goes to the end.\n\nIch ziehe einen Pullover an.\nSie zieht ihre Stiefel an.\n\nThe opposite is ausziehen (to take off):\nEr zieht seinen Mantel aus."},
{type:"mc",q:"Welches Wort bedeutet 'glasses'?",opts:["die Bluse","die Brille","die Hose","die Jeans"],ans:"die Brille",hint:"This word comes from a gemstone name."},
{type:"fb",s:"Levi Strauss war Deutscher. Er hat die {1} erfunden.",a:"Jeans",opts:["Jeans","Brille","Mütze","Bluse"],hint:"A famous type of pants from Bavaria.",sSrc:"Levi Strauss was German. He invented jeans."},
{type:"mc",q:"Was trägst du bei Regen?",opts:["eine Mütze","einen Anzug","einen Schirm","ein Kleid"],ans:"einen Schirm",hint:"Think of what keeps you dry when water falls from the sky."},
{type:"fb",s:"Für die Arbeit brauche ich einen {1} und ein Hemd.",a:"Anzug",opts:["Anzug","Rock","Pullover","Stiefel"],hint:"A formal outfit that you 'pull on' (anziehen).",sSrc:"For work I need a suit and a shirt."},
{type:"mc",q:"Was ist 'der Rock' auf Englisch?",opts:["rock music","coat","dress","skirt"],ans:"skirt",hint:"A piece of clothing, not a music genre."},
{type:"drag_fill",s:"Im Winter ziehe ich {1}, {2} und {3} an.",blanks:{"1":"Stiefel","2":"einen Mantel","3":"eine Mütze"},pool:["Stiefel","einen Mantel","eine Mütze","ein T-Shirt","einen Rock"],hint:"Think about what keeps you warm from head to toe.",sSrc:"In winter I put on boots, a coat and a beanie."},
{type:"match",pairs:[{trg:"der Mantel",src:"the coat"},{trg:"die Mütze",src:"the beanie"},{trg:"der Stiefel",src:"the boot"},{trg:"die Hose",src:"the pants"},{trg:"das Kleid",src:"the dress"},{trg:"die Brille",src:"the glasses"}]},

{type:"mc",q:"Welches Kleidungsstück ist immer Neutrum (das)?",opts:["der Mantel und der Rock","das Hemd und das Kleid","die Hose und die Jeans","die Bluse und die Mütze"],ans:"das Hemd und das Kleid",hint:"Look for the neuter articles among the clothing words you learned."},
{type:"fb",s:"Kleider machen {1}.",a:"Leute",opts:["Leute","Kleider","Schuhe","Sachen"],hint:"A famous proverb about how clothes affect perception of people.",sSrc:"Clothes make people."},
{type:"story",speaker:"hildi",mood:"satisfied",art:"de-ber-verumius-bundled",trg:"So. Mantel, Mütze, Schal, Handschuhe. Jetzt siehst du aus wie ein Berliner im Winter.",src:"There. Coat, hat, scarf, gloves. Now you look like a Berliner in winter."},
{type:"story",speaker:"verumius",mood:"sheepish",art:"de-ber-gendarmenmarkt-warm",trg:"Ich kann meine Arme nicht mehr bewegen, Hildi.",src:"I can no longer move my arms, Hildi."}
]},

// Unit 11, Lesson 3: Opa Heinrichs Brötchen
// Story dev + grammar intro: adjective declension (nominative) + temporal prepositions
// 8 vocab teach cards + verb_table + tip + 8 quiz steps = 24 steps total

{id:"deu_r11l3",title:"Opa Heinrichs Brötchen",icon:"🍞",xp:15,board:true,steps:[
{type:"intro",title:"Opa Heinrichs Brötchen",desc:"A man in a wool coat and flat cap appears at the Weihnachtsmarkt. He has bread from this morning and opinions about everything. Meet Opa Heinrich.",goals:["Learn 8 new words for gifts and shopping","Understand adjective endings in nominative case","Use temporal prepositions to talk about time"]},

{type:"story",speaker:"narrator",mood:"anticipating",art:"de-ber-weihnachtsmarkt-bench",trg:"Hildi bleibt an einer Bank neben dem Bratwurststand stehen. Sie schaut in die Menge, als ob sie jemanden sucht. Dann lächelt sie.",src:"Hildi stops at a bench near the bratwurst stand. She looks into the crowd as if searching for someone. Then she smiles."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-weihnachtsmarkt-opa",trg:"Ein alter Mann kommt langsam durch die Menge. Wollmantel, Schiebermütze, eine Tüte Brötchen unter dem Arm. Er sieht Hildi und winkt. 'Von heute Morgen,' sagt er und hält die Tüte hoch. 'Noch frisch!'",src:"An old man comes slowly through the crowd. Wool coat, flat cap, a bag of bread rolls under his arm. He sees Hildi and waves. 'From this morning,' he says, holding up the bag. 'Still fresh!'"},
{type:"story",speaker:"hildi",mood:"proud",trg:"Verumius, das ist mein Opa Heinrich. Opa, das ist Verumius. Er lernt Deutsch.",src:"Verumius, this is my grandpa Heinrich. Grandpa, this is Verumius. He is learning German."},
{type:"story",speaker:"opa",mood:"welcoming",trg:"Ah, der neue Freund! Hier, nimm ein frisches Brötchen. Nach dem Frühstück habe ich noch zehn übrig. Vor einer Stunde waren es zwölf.",src:"Ah, the new friend! Here, take a fresh bread roll. After breakfast I still had ten left. An hour ago there were twelve."},
{type:"teach",trg:"die Kette",
  pos:"noun",
  gender:"f",src:"the necklace / the chain",note:"Feminine noun. Plural: die Ketten.",example:"A: Die goldene Kette ist schön!\nB: Ja, die ist seit gestern im Angebot.",exampleSrc:"A: The golden necklace is beautiful!\nB: Yes, it has been on sale since yesterday.",funFact:"'Kette' means both 'necklace' and 'chain.' A bicycle chain is also 'eine Kette.' Context tells you if it is jewelry or hardware."},
{type:"teach",trg:"das Parfüm",
  pos:"noun",
  gender:"n",src:"the perfume",note:"Neuter noun. Plural: die Parfüms. Borrowed from French.",example:"A: Das teure Parfüm riecht toll!\nB: Ich schenke es meiner Mutter nach Weihnachten.",exampleSrc:"A: The expensive perfume smells great!\nB: I'll give it to my mother after Christmas.",funFact:"Germans borrowed 'Parfüm' straight from French 'parfum.' The umlaut ü was added to match German pronunciation. Many luxury words in German are French imports."},
{type:"teach",trg:"die Kosmetik",
  pos:"noun",
  gender:"f",src:"the cosmetics",note:"Feminine noun. Used as singular for the category.",example:"A: Wo finde ich gute Kosmetik?\nB: Seit letztem Jahr gibt es einen neuen Stand hier.",exampleSrc:"A: Where can I find good cosmetics?\nB: Since last year there has been a new stall here.",funFact:"From Greek 'kosmetikos' meaning 'skilled in decorating.' The same root gives us 'cosmos,' because the Greeks thought the universe was beautifully ordered."},
{type:"teach",trg:"die Mode",
  pos:"noun",
  gender:"f",src:"the fashion",note:"Feminine noun. From French 'mode.'",example:"A: Ist diese Mode noch modern?\nB: Ja, vor zwei Wochen war sie auf Instagram!",exampleSrc:"A: Is this fashion still modern?\nB: Yes, two weeks ago it was on Instagram!",funFact:"'Mode' and 'modern' share the same Latin root 'modus' (way, style). In German, 'altmodisch' (old-fashioned) literally means 'old-mode-ish.'"},
{type:"mc",q:"Opa Heinrich says 'Von heute Morgen, noch frisch!' What is he talking about?",opts:["His bread rolls","His wool coat","His flat cap","His necklace"],ans:"His bread rolls",hint:"He is carrying a bag of something baked under one arm."},
{type:"teach",trg:"die Ferien",
  pos:"noun",
  gender:"pl",src:"the holidays / the vacation",note:"Always plural in German. No singular form.",example:"A: Was machst du in den Ferien?\nB: Während der Ferien fahre ich nach Spanien.",exampleSrc:"A: What are you doing during the holidays?\nB: During the holidays I'm going to Spain.",funFact:"'Ferien' is always plural. For a single day off, Germans say 'Feiertag' (celebration-day). School holidays are 'Schulferien,' and summer break is 'Sommerferien.'"},
{type:"teach",trg:"der Flohmarkt",
  pos:"noun",
  gender:"m",src:"the flea market",note:"Masculine noun. Compound: Floh (flea) + Markt (market).",example:"A: Auf dem alten Flohmarkt gibt es schöne Ketten.\nB: Stimmt, seit letztem Monat ist er noch größer.",exampleSrc:"A: At the old flea market there are beautiful necklaces.\nB: True, since last month it is even bigger.",funFact:"'Flohmarkt' is a direct loan-translation from French 'marché aux puces.' The story goes that old clothes sold at these markets often had fleas in them!"},
{type:"teach",trg:"schenken",
  pos:"verb",
  gender:null,src:"to give (as a gift)",note:"Regular verb. Different from 'geben' (to give). Schenken = always a gift.",example:"A: Was schenkst du ihr?\nB: Ich schenke ihr eine neue Kette vor ihrem Geburtstag.",exampleSrc:"A: What are you giving her?\nB: I'm giving her a new necklace before her birthday.",funFact:"'Schenken' comes from 'einschenken' (to pour a drink). Originally, offering someone a drink was the act of giving. The meaning broadened to any gift."},
{type:"teach",trg:"wünschen",
  pos:"verb",
  gender:null,src:"to wish",note:"Regular verb. 'Ich wünsche dir alles Gute!' = I wish you all the best!",example:"A: Was wünschst du dir zu Weihnachten?\nB: Ich wünsche mir ein gutes Parfüm.",exampleSrc:"A: What do you wish for for Christmas?\nB: I wish for a nice perfume.",funFact:"The reflexive 'sich wünschen' means 'to wish for oneself.' A Wunschzettel is a 'wish-list' that German children write for Weihnachten."},
{type:"teach",trg:"der Schal",
  pos:"noun",src:"the scarf",gender:"m",phonetic:"SHAHL",example:"A: Dein Schal ist wirklich schön!\nB: Danke, ich habe ihn auf dem Weihnachtsmarkt gekauft.\nA: Die Farbe passt perfekt zu deinem Mantel.",exampleSrc:"A: Your scarf is really beautiful!\nB: Thanks, I bought it at the Christmas market.\nA: The color matches your coat perfectly.",note:"der Schal, masculine. Plural: die Schals. A winter essential on the Weihnachtsmarkt.",funFact:"The German word 'Schal' comes from Persian via French. Cashmere scarves from Kashmir were luxury items in 18th century Europe."},
{type:"mc",q:"'Ich schenke dir eine Kette.' What is the speaker doing?",opts:["Buying a necklace for themselves","Giving a necklace as a gift","Borrowing a necklace","Returning a necklace"],ans:"Giving a necklace as a gift",hint:"What is the speaker doing with the jewellery? Think about whether it is an exchange, a loan, or a free permanent gesture."},
{type:"verb_table",title:"Adjective Endings: Nominative Case",groups:[{label:"After der/die/das (definite article): always -e",rows:[{pronoun:"der",form:"-e",src:"der alte Mann (the old man)"},{pronoun:"die",form:"-e",src:"die goldene Kette (the golden necklace)"},{pronoun:"das",form:"-e",src:"das teure Parfüm (the expensive perfume)"},{pronoun:"die (pl.)",form:"-en",src:"die frischen Brötchen (the fresh rolls)"}]},

{label:"After ein/eine/ein (indefinite article)",rows:[{pronoun:"ein (masc.)",form:"-er",src:"ein alter Mann (an old man)"},{pronoun:"eine (fem.)",form:"-e",src:"eine goldene Kette (a golden necklace)"},{pronoun:"ein (neut.)",form:"-es",src:"ein teures Parfüm (an expensive perfume)"}]},

{label:"No article (strong endings)",rows:[{pronoun:"masc.",form:"-er",src:"frischer Kaffee (fresh coffee)"},{pronoun:"fem.",form:"-e",src:"gute Kosmetik (good cosmetics)"},{pronoun:"neut.",form:"-es",src:"kaltes Wasser (cold water)"},{pronoun:"plural",form:"-e",src:"frische Brötchen (fresh rolls)"}]}],note:"After definite articles, adjectives are 'weak' and almost always end in -e (except plural: -en). After indefinite articles, the adjective shows the gender."},
{type:"tip",title:"Temporal Prepositions: When Did It Happen?",text:"German uses specific prepositions for time expressions:\n\nvor (before, ago) takes the dative:\n- 'Vor einer Stunde' = an hour ago\n- 'Vor dem Frühstück' = before breakfast\n\nnach (after) takes the dative:\n- 'Nach dem Essen' = after the meal\n- 'Nach Weihnachten' = after Christmas\n\nwährend (during) takes the genitive:\n- 'Während der Ferien' = during the holidays\n\nbis (until) needs no article:\n- 'Bis morgen!' = Until tomorrow!\n\nseit (since, for ongoing situations) takes the dative:\n- 'Seit gestern' = since yesterday\n- 'Seit zwei Wochen' = for two weeks\n\nab (from a point in time) takes the dative:\n- 'Ab morgen' = from tomorrow on",deepDive:"'Vor' and 'nach' are the most common pair. Think of them as opposites on a timeline: vor = to the left (earlier), nach = to the right (later). 'Seit' describes something that STARTED in the past and CONTINUES now. 'Bis' marks where something ENDS."},
{type:"mc",q:"Opa Heinrich says 'Vor einer Stunde waren es zwölf.' What does 'vor einer Stunde' mean?",opts:["In one hour","For one hour","An hour ago","Before one hour"],ans:"An hour ago",hint:"'Vor' with a time expression looks backward on the timeline."},
{type:"fb",s:"{1} dem Frühstück habe ich noch zehn übrig.",a:["Nach"],opts:["Nach","Vor","Seit","Bis"],hint:"Which preposition means 'after' with a past event?",sSrc:"After breakfast I have ten left."},
{type:"mc",q:"'Die goldene Kette ist schön.' Why does the adjective end in -e?",opts:["Because 'Kette' is feminine","Because 'golden' always ends in -e","Because the sentence is about beauty","Because it follows 'die' (definite article)"],ans:"Because it follows 'die' (definite article)",hint:"Look at the determiner directly before the descriptor. When gender is already shown by that determiner, the following word takes a minimal 'weak' ending."},
{type:"fb",s:"Ein alt{1} Mann kommt durch die Menge.",a:["er"],opts:["er","e","es","en"],hint:"After 'ein' in nominative, what ending does the adjective need for a masculine noun?",sSrc:"An old man comes through the crowd."},
{type:"drag_fill",s:"Ich wünsche mir {1} Parfüm {2} Weihnachten.",blanks:{"1":"ein gutes","2":"vor"},pool:["ein gutes","eine gute","ein guter","vor","nach","seit"],hint:"A neuter noun after 'ein' needs which ending? And which preposition means 'before'?",sSrc:"I wish for a good perfume before Christmas."},
{type:"mc",q:"'Seit letztem Jahr gibt es einen neuen Stand.' What does 'seit' tell you?",opts:["It started last year and continues now","It happened once last year","It will happen next year","It ended last year"],ans:"It started last year and continues now",hint:"This preposition describes something ongoing from a past starting point."},
{type:"teach",trg:"während",src:"while / during",pos:"conj",gender:null,note:"Two uses: conjunction (while) + subordinating clause; preposition (during) + genitive.",example:"A: Was machst du während der Ferien?\nB: Ich lese, während die Kinder spielen.\nA: Das klingt entspannend!\nB: Ja, während der Ferien brauche ich Ruhe.",exampleSrc:"A: What do you do during the holidays?\nB: I read while the children play.\nA: That sounds relaxing!\nB: Yes, I need quiet during the holidays.",funFact:"Während is one of the few German words that works as both a conjunction and a preposition. As a conjunction it means 'while'; as a preposition it means 'during' and takes the genitive case."},
{type:"fb",s:"{1} der Ferien fahre ich nach Spanien.",a:["Während"],opts:["Während","Seit","Vor","Ab"],hint:"Which preposition means 'during' and takes the genitive case?",sSrc:"During the holidays I am travelling to Spain."},
{type:"drag_fill",s:"{1} Brötchen sind {2} heute Morgen.",blanks:{"1":"Die frischen","2":"von"},pool:["Die frischen","Das frische","Der frischer","von","vor","nach"],hint:"Definite article + plural adjective ending? And 'from' this morning?",sSrc:"The fresh rolls are from this morning."},
{type:"match",pairs:[{trg:"die Kette",src:"the necklace"},{trg:"schenken",src:"to give (as gift)"},{trg:"wünschen",src:"to wish"},{trg:"die Ferien",src:"the holidays"},{trg:"vor",src:"ago / before"},{trg:"seit",src:"since / for"}]},

{type:"story",speaker:"opa",mood:"nostalgic",trg:"Hier, frische Brötchen für alle! Seit fünfzig Jahren kaufe ich beim gleichen Bäcker. Vor dem Krieg war der Laden noch klein. Während der Ferien backt er sogar Stollen!",src:"Here, fresh rolls for everyone! For fifty years I have been buying from the same baker. Before the war the shop was still small. During the holidays he even bakes Stollen!"},
{type:"story",speaker:"verumius",mood:"touched",art:"de-ber-weihnachtsmarkt-broetchen",trg:"Verumius beißt in das Brötchen. Es ist frisch, weich und noch ein bisschen warm. Er sieht Heinrich an. Er sieht Hildi an. Er sagt nichts. Aber er lächelt.",src:"Verumius bites into the bread roll. It is fresh, soft, and still a little warm. He looks at Heinrich. He looks at Hildi. He says nothing. But he smiles."},
{type:"mc",q:"Opa Heinrich says 'Seit fünfzig Jahren kaufe ich beim gleichen Bäcker.' How long has he been going to the same baker?",opts:["For five years","For fifty years","For fifteen years","Since his birthday"],ans:"For fifty years",hint:"'Fünfzig' is the German word for a number between 49 and 51."}
]},

// U11 L4: Der rote Schal - Grammar: Adjective declension (acc/dat), possessives, Konjunktiv II
{id:"deu_r11l4",title:"Der rote Schal",icon:"\uD83D\uDCD0",xp:20,board:true,steps:[
{type:"intro",title:"Der rote Schal",desc:"Verumius spots a beautiful red scarf at the Weihnachtsmarkt. But describing it means mastering adjective endings in accusative and dative. Plus: how to say 'I would like...'",goals:["Decline adjectives in accusative and dative","Use possessive articles across cases","Express wishes with w\u00fcrde + infinitive"]},

{type:"story",speaker:"narrator",mood:"festive",art:"de-xmas-market-walking",trg:"Sie gehen weiter durch den Markt. Heinrich links, Hildi rechts, Verumius in der Mitte. Wie eine kleine Familie an Heiligabend.",src:"They walk on through the market. Heinrich on the left, Hildi on the right, Verumius in the middle. Like a small family on Christmas Eve."},
{type:"story",speaker:"narrator",mood:"curious",art:"de-xmas-market-scarves",trg:"Am Schalstand. Bunte Schals h\u00e4ngen \u00fcberall. Verumius sieht einen roten Schal und greift danach. Hildi lacht.",src:"At the scarf stand. Colorful scarves hang everywhere. Verumius sees a red scarf and reaches for it. Hildi laughs."},
{type:"story",speaker:"hildi",mood:"amused",trg:"Du willst den roten Schal? Der passt zu deinem blauen Mantel. Aber ich w\u00fcrde den gr\u00fcnen nehmen!",src:"You want the red scarf? It goes with your blue coat. But I would take the green one!"},
{type:"teach",trg:"beschreiben",
  pos:"verb",
  gender:null,src:"to describe",note:"Irregular (strong verb): ich beschreibe, du beschreibst, er beschreibt. Past: beschrieb, Partizip II: beschrieben.",example:"A: Kannst du den Schal beschreiben?\nB: Er ist lang, rot und sehr weich.",exampleSrc:"A: Can you describe the scarf?\nB: It is long, red, and very soft.",funFact:"'Beschreiben' literally means 'to write upon.' You 'write upon' something with words to paint a picture. The same 'schreiben' root appears in 'Schreibtisch' (writing desk)."},
{type:"teach",trg:"passen",
  pos:"verb",
  gender:null,src:"to fit / to suit",note:"Regular: ich passe, du passt, er passt. Often used with 'zu' (to/with).",example:"A: Passt der Schal zu meinem Mantel?\nB: Ja, die Farben passen perfekt zusammen!",exampleSrc:"A: Does the scarf go with my coat?\nB: Yes, the colors match perfectly!",funFact:"'Das passt!' is how Germans say 'That works!' In restaurants, 'Passt so' after paying means 'keep the change.' One little verb, many daily uses."},
{type:"teach",trg:"tragen",
  pos:"verb",
  gender:null,src:"to wear / to carry",note:"Irregular: ich trage, du tr\u00e4gst, er tr\u00e4gt. Stem change a \u2192 \u00e4.",example:"A: Was tr\u00e4gst du heute?\nB: Ich trage einen warmen Pullover.",exampleSrc:"A: What are you wearing today?\nB: I'm wearing a warm sweater.",funFact:"'Tragen' means both 'to wear' and 'to carry.' A 'Gep\u00e4cktr\u00e4ger' is a luggage carrier. Context decides whether clothes or cargo are involved."},
{type:"teach",trg:"vergleichen",
  pos:"verb",
  gender:null,src:"to compare",note:"Irregular past, but regular present: ich vergleiche, du vergleichst.",example:"A: Lass uns die zwei Schals vergleichen.\nB: Der rote ist weicher als der blaue.",exampleSrc:"A: Let's compare the two scarves.\nB: The red one is softer than the blue one.",funFact:"'Vergleichen' contains 'gleich' (same/equal). To compare is literally to 'check for sameness.' 'Gleich' also means 'soon' in casual speech: 'Ich komme gleich!'"},
{type:"teach",trg:"wechseln",
  pos:"verb",
  gender:null,src:"to change / to exchange",note:"Regular: ich wechsle, du wechselst. Used for money, clothes, or topics.",example:"A: Kann ich den Schal wechseln?\nB: Nat\u00fcrlich, gegen welche Farbe?",exampleSrc:"A: Can I exchange the scarf?\nB: Of course, for which color?",funFact:"A 'Wechselstube' is a currency exchange booth. 'Geld wechseln' = to exchange money. At the Weihnachtsmarkt, you might need to 'wechseln' big bills for small coins."},
{type:"teach",trg:"ansehen",
  pos:"verb",
  gender:null,src:"to look at",note:"Separable: ich sehe ... an, du siehst ... an. Stem change e \u2192 ie.",example:"A: Sieh dir den Schal an!\nB: Oh, der ist wirklich sch\u00f6n!",exampleSrc:"A: Look at the scarf!\nB: Oh, it is really beautiful!",funFact:"'Ansehen' is separable: the 'an' jumps to the end of the clause. 'Ich sehe den Schal an.' But in a subordinate clause it reunites: 'weil ich den Schal ansehe.' German word Tetris!"},
{type:"mc",q:"Which verb means 'to wear' or 'to carry' in German?",opts:["tragen","passen","wechseln","beschreiben"],ans:"tragen",hint:"This irregular verb has a stem change from a to \u00e4 in the du/er forms."},
{type:"tip",title:"Adjective Endings: The Big Picture",text:"German adjectives change their ending based on THREE things:\n\n1. Case: nominative, accusative, or dative?\n2. Gender: der, die, or das?\n3. Article type: definite (der/die/das) or indefinite (ein/eine/ein)?\n\nYou already know nominative from L3.\nNow we add accusative (direct object) and dative (indirect object).\n\nGood news: there are PATTERNS that simplify everything.",deepDive:"Why does German do this? Because adjective endings carry grammatical information. In 'Ich sehe den roten Schal,' the '-en' on 'roten' confirms this is accusative masculine. Even if you missed 'den,' the adjective ending tells you the case. It is a backup system built into the language."},
{type:"verb_table",title:"Adjective Declension: Accusative Case",groups:[{label:"With definite article (den/die/das)",rows:[{pronoun:"Masculine",form:"den rot-en Schal",src:"the red scarf (-en)"},{pronoun:"Feminine",form:"die rot-e M\u00fctze",src:"the red hat (-e)"},{pronoun:"Neuter",form:"das rot-e Kleid",src:"the red dress (-e)"}]},

{label:"With indefinite article (einen/eine/ein)",rows:[{pronoun:"Masculine",form:"einen rot-en Schal",src:"a red scarf (-en)"},{pronoun:"Feminine",form:"eine rot-e M\u00fctze",src:"a red hat (-e)"},{pronoun:"Neuter",form:"ein rot-es Kleid",src:"a red dress (-es)"}]}],note:"Accusative masculine always gets -en. Feminine stays -e. Neuter: -e with definite, -es with indefinite (because 'ein' has no ending to show gender)."},
{type:"mc",q:"'Ich kaufe _____ warmen Schal.' Which article completes this accusative masculine phrase?",opts:["die","den","das","dem"],ans:"den",hint:"Accusative changes only the masculine article from 'der' to something else."},
{type:"fb",s:"Hildi kauft {1} roten Schal f\u00fcr Opa.",a:["einen"],opts:["einen","ein","einem","einer"],hint:"Schal is masculine. Accusative case with an indefinite article is needed here.",sSrc:"Hildi buys a red scarf for grandpa."},
{type:"mc",q:"'Hildi sieht die sch\u00f6n___ Lampe an.' Which ending fits this accusative feminine phrase?",opts:["-en","-es","-e","-em"],ans:"-e",hint:"Accusative feminine with 'die' keeps the same ending as nominative feminine."},
{type:"fb",s:"Ich m\u00f6chte ein warm{1} Kleid kaufen.",a:["es"],opts:["es","e","en","em"],hint:"Accusative neuter with 'ein' needs an ending that shows neuter gender.",sSrc:"I would like to buy a warm dress."},
{type:"verb_table",title:"Adjective Declension: Dative Case",groups:[{label:"With definite article (dem/der/dem)",rows:[{pronoun:"Masculine",form:"dem rot-en Schal",src:"the red scarf (-en)"},{pronoun:"Feminine",form:"der rot-en M\u00fctze",src:"the red hat (-en)"},{pronoun:"Neuter",form:"dem rot-en Kleid",src:"the red dress (-en)"}]},

{label:"With indefinite article (einem/einer/einem)",rows:[{pronoun:"Masculine",form:"einem rot-en Schal",src:"a red scarf (-en)"},{pronoun:"Feminine",form:"einer rot-en M\u00fctze",src:"a red hat (-en)"},{pronoun:"Neuter",form:"einem rot-en Kleid",src:"a red dress (-en)"}]}],note:"Dative is the EASY case for adjectives: EVERY ending is -en. Always. No exceptions. Masculine, feminine, neuter, definite, indefinite: always -en."},
{type:"tip",title:"Dative Shortcut: Always -en!",text:"Dative adjective endings are the simplest in German:\n\ndem kalten Wind = -en\nder warmen Suppe = -en\ndem alten Haus = -en\neinem neuen Freund = -en\n\nAll genders. All article types. Always -en.\nThis is the one case you can learn in five seconds.",deepDive:"Why always -en? In dative, the article itself already shows the gender clearly (dem = masc/neut, der = fem). The adjective does not need to carry extra gender information, so it relaxes to the default -en ending. Less work for the adjective when the article is already doing the job."},
{type:"fb",s:"Ich gebe es dem klein{1} Kind.",a:["en"],opts:["en","e","es","em"],hint:"In dative, adjective endings follow one universal rule for all genders.",sSrc:"I give it to the small child."}
]},

// ─── Lesson: Besitz und Wünsche ───
{id:"deu_r11l5",title:"Besitz und Wünsche",icon:"🎁",xp:15,board:true,steps:[
{type:"intro",title:"Besitz und Wünsche",desc:"Possessive articles work like ein-words, and Konjunktiv II lets you express wishes. From warm cups of tea to red scarves, learn to talk about what belongs to you and what you would like.",goals:["Use possessive articles with adjective endings","Express wishes with Konjunktiv II (würde + infinitive)","Combine adjective declension with possessives"]},
{type:"teach",trg:"die Tasse",
  pos:"noun",src:"the cup",gender:"f",phonetic:"TA-suh",example:"A: Möchtest du eine Tasse Tee?\nB: Ja, gerne! Mit Zucker, bitte.\nA: Hier, eine warme Tasse für dich.",exampleSrc:"A: Would you like a cup of tea?\nB: Yes, please! With sugar.\nA: Here, a warm cup for you.",note:"die Tasse, feminine. Plural: die Tassen. Used for cups with handles, including mugs.",funFact:"Germans drink about 164 litres of coffee per person per year. On the Weihnachtsmarkt, Glühwein comes in collectible Tassen you can keep."},
{type:"mc",q:"'Mit einer warm___ Tasse Tee.' Which ending completes this dative phrase?",opts:["-e","-es","-er","-en"],ans:"-en",hint:"Dative adjectives follow one universal rule regardless of gender or article type."},
{type:"drag_fill",s:"Verumius gibt {1} Frau {2} Schal.",blanks:{"1":"der netten","2":"den roten"},pool:["der netten","den roten","die nette","das rote","dem netten"],hint:"'Der Frau' is dative feminine. 'Den Schal' is accusative masculine. Pick the matching adjective forms.",sSrc:"Verumius gives the nice woman the red scarf."},
{type:"verb_table",title:"Possessive Articles: mein/dein/sein/ihr",groups:[{label:"Nominative",rows:[{pronoun:"Masculine",form:"mein roter Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meine rote M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"mein rotes Kleid",src:"my red dress"}]},

{label:"Accusative",rows:[{pronoun:"Masculine",form:"meinen roten Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meine rote M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"mein rotes Kleid",src:"my red dress"}]},

{label:"Dative",rows:[{pronoun:"Masculine",form:"meinem roten Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meiner roten M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"meinem roten Kleid",src:"my red dress"}]}],note:"Possessives (mein/dein/sein/ihr/unser/euer/ihr) follow the SAME pattern as ein/eine/ein. Just swap 'ein' for 'mein' and adjective endings stay identical."},
{type:"tip",title:"Possessives = ein-Words",text:"Great news: mein, dein, sein, ihr, unser, euer, ihr, and kein all follow the EXACT same pattern as ein/eine/ein.\n\nIf you know 'einen roten Schal,' you know:\nmeinen roten Schal\ndeinen roten Schal\nseinen roten Schal\nihren roten Schal\n\nOne pattern, eight words. Learn it once, use it everywhere.",deepDive:"The possessives are called 'ein-words' because they take the same endings as 'ein.' The definite article words (dieser, jeder, welcher) are called 'der-words' and follow 'der/die/das' endings. Knowing which group a word belongs to tells you all its endings automatically."},
{type:"fb",s:"Hildi tr\u00e4gt {1} neuen Schal.",a:["ihren"],opts:["ihren","ihre","ihr","ihrem"],hint:"Accusative masculine with a possessive follows the same pattern as 'einen.'",sSrc:"Hildi wears her new scarf."},
{type:"mc",q:"'Ich gebe es meinem alten Freund.' What case is 'meinem alten' in?",opts:["Accusative","Nominative","Dative","Genitive"],ans:"Dative",hint:"'Meinem' with -em ending signals the case used for giving things TO someone."},
{type:"tip",title:"Konjunktiv II: Wishes and Polite Requests",text:"To say 'I would...' in German, use:\nw\u00fcrde + infinitive (at the end)\n\nIch w\u00fcrde den Schal kaufen. = I would buy the scarf.\nW\u00fcrdest du mir helfen? = Would you help me?\n\nFour common verbs have their OWN Konjunktiv II forms:\nw\u00e4re (would be), h\u00e4tte (would have),\nk\u00f6nnte (could), m\u00fcsste (would have to).",deepDive:"Konjunktiv II comes from the simple past (Pr\u00e4teritum) form with an umlaut added. 'War' becomes 'w\u00e4re,' 'hatte' becomes 'h\u00e4tte,' 'konnte' becomes 'k\u00f6nnte.' For most verbs, this old form sounds archaic, so modern German uses 'w\u00fcrde + infinitive' instead. But the four common ones (w\u00e4re, h\u00e4tte, k\u00f6nnte, m\u00fcsste) are used daily."},
{type:"verb_table",title:"Konjunktiv II: w\u00fcrde + Infinitive",groups:[{label:"w\u00fcrde (would)",rows:[{pronoun:"ich",form:"w\u00fcrde",src:"I would"},{pronoun:"du",form:"w\u00fcrdest",src:"you would"},{pronoun:"er/sie/es",form:"w\u00fcrde",src:"he/she/it would"},{pronoun:"wir",form:"w\u00fcrden",src:"we would"},{pronoun:"ihr",form:"w\u00fcrdet",src:"you all would"},{pronoun:"sie/Sie",form:"w\u00fcrden",src:"they/you (formal) would"}]},

{label:"Common irregular forms",rows:[{pronoun:"sein",form:"w\u00e4re",src:"would be"},{pronoun:"haben",form:"h\u00e4tte",src:"would have"},{pronoun:"k\u00f6nnen",form:"k\u00f6nnte",src:"could"},{pronoun:"m\u00fcssen",form:"m\u00fcsste",src:"would have to"}]}],note:"Use w\u00fcrde + infinitive for most verbs. Use w\u00e4re/h\u00e4tte/k\u00f6nnte/m\u00fcsste directly (no w\u00fcrde needed). 'Ich w\u00fcrde kaufen' but 'Ich h\u00e4tte gern...'"},
{type:"mc",q:"Hildi says 'Ich w\u00fcrde den gr\u00fcnen nehmen!' What does 'w\u00fcrde ... nehmen' mean?",opts:["must take","will take","would take","should take"],ans:"would take",hint:"This construction expresses a hypothetical wish, not certainty or obligation."},
{type:"fb",s:"Ich {1} gern einen Gl\u00fchwein trinken.",a:["w\u00fcrde"],opts:["w\u00fcrde","w\u00e4re","h\u00e4tte","k\u00f6nnte"],hint:"Which word means 'would' and combines with an infinitive at the end?",sSrc:"I would like to drink a mulled wine."},
{type:"mc",q:"'Das w\u00e4re sehr nett!' What does 'w\u00e4re' mean?",opts:["would have","could","would be","would have to"],ans:"would be",hint:"This irregular Konjunktiv II form comes from 'sein' (to be)."},
{type:"drag_fill",s:"Ich {1} gern {2} roten Schal f\u00fcr {3} Freundin kaufen.",blanks:{"1":"w\u00fcrde","2":"den","3":"meine"},pool:["w\u00fcrde","den","meine","w\u00e4re","dem","meiner"],hint:"Express a wish (would), then accusative masc. article, then accusative fem. possessive.",sSrc:"I would like to buy the red scarf for my girlfriend."},
{type:"mc",q:"'Wenn ich reich ___, ___ ich alles kaufen.' Which pair completes this?",opts:["w\u00fcrde ... w\u00e4re","w\u00e4re ... w\u00fcrde","h\u00e4tte ... w\u00e4re","k\u00f6nnte ... h\u00e4tte"],ans:"w\u00e4re ... w\u00fcrde",hint:"First blank needs the Konjunktiv II of 'sein,' second needs 'would' with an infinitive."},
{type:"match",pairs:[{trg:"den roten Schal",src:"the red scarf (acc.)"},{trg:"dem kalten Wind",src:"the cold wind (dat.)"},{trg:"meinen neuen Mantel",src:"my new coat (acc.)"},{trg:"einer warmen Tasse",src:"a warm cup (dat.)"},{trg:"w\u00fcrde kaufen",src:"would buy"},{trg:"w\u00e4re",src:"would be"}]},

{type:"mc",q:"Which word expresses a polite wish in German?",opts:["hatte","wuerde + infinitive","ist","wird"],ans:"wuerde + infinitive",hint:"This construction means would + verb. It expresses hypothetical wishes politely."},
{type:"story",speaker:"opa",mood:"wise",art:"de-xmas-market-scarves",trg:"Heinrich kauft den roten Schal. Verumius protestiert. Heinrich winkt ab. 'In meinem Alter gibt man. Das ist das Schönste.'",src:"Heinrich buys the red scarf. Verumius protests. Heinrich waves it off. 'At my age, you give. That is the most beautiful thing.'"}
]},

{id:"deu_r11l6",title:"Wie ist das Wetter?",icon:"🌨️",xp:10,board:true,steps:[
{type:"intro",title:"Wie ist das Wetter?",desc:"Snow falls at the Christmas market. Learn to talk about weather in German.",goals:["Learn 11 weather words and adjectives","Describe temperature, wind, and sky conditions","Use weather small talk patterns"]},

{type:"story",speaker:"narrator",mood:"atmospheric",art:"de-ber-gendarmenmarkt-snow-falling",trg:"Der Wind dreht. Kleine Schneeflocken tanzen zwischen den Lichtern. Verumius hält die Hände um seine Tasse. Heiße Schokolade. Dampf steigt auf.",src:"The wind shifts. Small snowflakes dance between the lights. Verumius wraps his hands around his cup. Hot chocolate. Steam rises."},
{type:"story",speaker:"opa",mood:"nostalgic",art:"de-ber-gendarmenmarkt-snow-bench",trg:"Damals, als ich jung war, gab es kälteren Schnee. Nicht diesen modernen Schnee. Der Schnee von heute ist zu weich.",src:"Back then, when I was young, the snow was colder. Not this modern snow. Today's snow is too soft."},
{type:"teach",trg:"kalt",src:"cold",pos:"adj",gender:null,phonetic:"kahlt",example:"A: Ist es draußen kalt?\nB: Ja, es ist sehr kalt heute.",exampleSrc:"A: Is it cold outside?\nB: Yes, it is very cold today.",note:"The classic winter word. Kälte = the cold (noun).",funFact:"Germans talk about the weather constantly. 'Kalt, oder?' (cold, isn't it?) is a fully valid conversation opener."},
{type:"teach",trg:"kühl",src:"cool",pos:"adj",gender:null,phonetic:"küül",example:"A: Wie ist es abends auf dem Markt?\nB: Es wird kühl nach sechs Uhr.",exampleSrc:"A: How is it in the evening at the market?\nB: It gets cool after six o'clock.",note:"Milder than 'kalt.' Frische Luft = cool air.",funFact:"Kühl also describes people: 'Sie war sehr kühl zu mir' means she was distant or cold in manner."},
{type:"teach",trg:"warm",src:"warm",pos:"adj",gender:null,phonetic:"varm",example:"A: Der Glühwein ist schön warm.\nB: Ja, perfekt für kalte Hände!",exampleSrc:"A: The mulled wine is nicely warm.\nB: Yes, perfect for cold hands!",note:"Cognate with English. Wärme = warmth (noun).",funFact:"Mulled wine at Christmas markets is served in ceramic mugs that you can keep as a souvenir. A small deposit is included in the price."},
{type:"teach",trg:"heiß",src:"hot",pos:"adj",gender:null,phonetic:"haiß",example:"A: Vorsicht, die Suppe ist heiß!\nB: Danke, ich warte kurz.",exampleSrc:"A: Careful, the soup is hot!\nB: Thanks, I'll wait a moment.",note:"Also used for weather: Es ist heiß draußen.",funFact:"'Heißhunger' means a sudden, intense hunger. Literally 'hot hunger.' We would say 'ravenous hunger' in English."},
{type:"mc",q:"Was ist das Gegenteil von 'kalt'?",opts:["warm","kühl","heiß","trocken"],ans:"warm",hint:"A pleasant middle temperature, not extreme."},
{type:"fb",s:"Vorsicht, die Suppe ist sehr {1}!",a:"heiß",opts:["heiß","kühl","kalt","warm"],hint:"Extremely high temperature. It can burn your tongue.",sSrc:"Careful, the soup is very hot!"},
{type:"teach",trg:"nass",src:"wet",pos:"adj",gender:null,phonetic:"nass",example:"A: Meine Schuhe sind ganz nass.\nB: Es hat den ganzen Tag geregnet.",exampleSrc:"A: My shoes are completely wet.\nB: It has rained all day.",note:"Also: patschnass = soaking wet.",funFact:"German has many words for wet: feucht (damp), klamm (clammy), durchnässt (drenched), patschnass (soaking wet). Each captures a different degree."},
{type:"teach",trg:"trocken",src:"dry",pos:"adj",gender:null,phonetic:"trokken",example:"A: Bleibt es heute trocken?\nB: Ja, kein Regen bis Freitag.",exampleSrc:"A: Will it stay dry today?\nB: Yes, no rain until Friday.",note:"Opposite of nass. Also used for humor: trockener Witz = dry wit.",funFact:"'Trockener Humor' (dry humor) is typical in northern Germany, especially Hamburg. Deadpan delivery with no smiling."},
{type:"teach",trg:"sonnig",src:"sunny",pos:"adj",gender:null,phonetic:"zonnich",example:"A: Wie wird das Wetter morgen?\nB: Sonnig und warm, sagt die App.",exampleSrc:"A: How will the weather be tomorrow?\nB: Sunny and warm, the app says.",note:"From die Sonne (the sun). The -ig suffix turns nouns into adjectives.",funFact:"Berlin averages more sunshine hours than London, but fewer than Madrid. German summer days can be genuinely warm and bright."},
{type:"teach",trg:"windig",src:"windy",pos:"adj",gender:null,phonetic:"vindich",example:"A: Warum trägst du eine Mütze?\nB: Es ist sehr windig draußen.",exampleSrc:"A: Why are you wearing a hat?\nB: It is very windy outside.",note:"From der Wind. Same -ig suffix as sonnig.",funFact:"The North Sea coast is almost always windy. Frisians have a saying: 'Wind is just air here.' Northern Germany is famous for strong coastal winds."},
{type:"fb",s:"Meine Schuhe sind ganz {1} vom Regen.",a:"nass",opts:["nass","trocken","sonnig","windig"],hint:"Rain makes things the opposite of dry.",sSrc:"My shoes are completely wet from the rain."},
{type:"teach",trg:"der Wind",src:"the wind",pos:"noun",gender:"m",phonetic:"VINT",example:"A: Spürst du den kalten Wind?\nB: Ja, er kommt vom Fluss.\nA: Lass uns in die Hütte gehen.",exampleSrc:"A: Do you feel the cold wind?\nB: Yes, it is coming from the river.\nA: Let us go into the hut.",note:"der Wind, masculine. Plural: die Winde. Related adjective: windig (windy).",funFact:"Germany gets strong winds from the North Sea coast. The Beaufort scale is used in German weather reports: Windstarke 8 means gale force."},
{type:"teach",trg:"nebelig",src:"foggy",pos:"adj",gender:null,phonetic:"nebelich",example:"A: Ich sehe die Kirche nicht.\nB: Normal, es ist heute sehr nebelig.",exampleSrc:"A: I can't see the church.\nB: Normal, it is very foggy today.",note:"From der Nebel (fog). The -ig suffix creates the adjective.",funFact:"November fog in German river valleys can last for days. Meteorologists call this an 'Inversionswetterlage' (temperature inversion). Cold air gets trapped below warm air, holding the fog in place."},
{type:"teach",trg:"bewölkt",src:"cloudy",pos:"adj",gender:null,phonetic:"bevölkt",example:"A: Scheint die Sonne?\nB: Nein, es ist leider bewölkt.",exampleSrc:"A: Is the sun shining?\nB: No, it's unfortunately cloudy.",note:"From die Wolke (cloud). The be- prefix + -t ending forms this adjective.",funFact:"German weather forecasts distinguish between 'bewölkt' (cloudy), 'stark bewölkt' (heavily cloudy), and 'bedeckt' (completely overcast). Three levels of cloud cover."},
{type:"tip",title:"Deutsche und das Wetter",text:"Germans love talking about the weather. It is a perfect conversation starter.\n\nTypical questions:\n\n'Wie ist das Wetter?' (How is the weather? - general)\n'Wie wird es morgen?' (What will it be like tomorrow? - forecast)\n'Schönes Wetter heute, oder?' (Nice weather today, isn't it? - small talk)\n\nAnswer with 'Es ist...' + adjective:\nEs ist kalt. Es ist sonnig. Es ist bewölkt.",deepDive:"The word 'Wetter' appears in many compounds: Wetterbericht (weather report), Wetterdienst (weather service), Wettervorhersage (forecast), wetterbeständig (weatherproof). The question 'Na, wie ist das Wetter bei euch?' (So how is the weather there?) is a standard opener for phone calls with family."},
{type:"mc",q:"Verumius sagt: 'Brr! Es ist heute wirklich ___.' Was fehlt?",opts:["sonnig","kalt","trocken","warm"],ans:"kalt",hint:"'Brr' expresses that someone is not warm. What is the opposite of warm?"},
{type:"fb",s:"Meine Jacke ist ganz {1} vom Regen.",a:"nass",opts:["nass","trocken","warm","heiß"],hint:"Rain does not make clothing dry. Think of the opposite of trocken.",sSrc:"My jacket is completely wet from the rain."},
{type:"mc",q:"Hildi fragt: 'Wie wird das Wetter morgen?' Verumius antwortet: 'Die App sagt, es wird ___ und warm.'",opts:["nebelig","nass","sonnig","bewölkt"],ans:"sonnig",hint:"Warm weather usually comes with the sun, not fog or clouds."},
{type:"fb",s:"Vorsicht! Der Glühwein ist noch sehr {1}.",a:"heiß",opts:["heiß","kühl","trocken","windig"],hint:"Freshly poured mulled wine burns your tongue. Very high temperature.",sSrc:"Careful! The mulled wine is still very hot."},
{type:"mc",q:"Am Abend wird es auf dem Markt nicht kalt, sondern nur ___.",opts:["heiß","nass","sonnig","kühl"],ans:"kühl",hint:"A milder version of cold. Not freezing, just a bit chilly."},
{type:"mc",q:"Verumius fragt: 'Wie ist das Wetter heute?' Hildi antwortet: 'Es ist ___ und kalt.'",opts:["windig","fleißig","einzeln","typisch"],ans:"windig",hint:"Which word describes weather, not a person's character?"},
{type:"drag_fill",s:"Im November ist es oft {1} und {2}. Man sieht die Sonne nicht.",blanks:{"1":"bewölkt","2":"nebelig"},pool:["bewölkt","nebelig","sonnig","trocken"],hint:"Typical November weather: grey and misty. Two weather adjectives for poor visibility.",sSrc:"In November it is often cloudy and foggy. You cannot see the sun."},
{type:"match",pairs:[{trg:"kalt",src:"cold"},{trg:"heiß",src:"hot"},{trg:"nass",src:"wet"},{trg:"trocken",src:"dry"},{trg:"sonnig",src:"sunny"},{trg:"windig",src:"windy"}]},
{type:"fb",s:"Der Gl\u00fchwein ist sch\u00f6n {1}. Perfekt f\u00fcr kalte H\u00e4nde!",a:"warm",opts:["warm","kalt","nass","trocken"],hint:"The opposite of cold. A pleasant temperature for a winter drink.",sSrc:"The mulled wine is nicely warm. Perfect for cold hands!"},
{type:"fb",s:"Der {1} bläst heute stark. Halt deine Mütze fest!",a:"Wind",opts:["Wind","Schnee","Nebel","Himmel"],hint:"Moving air that blows your hat off. A masculine noun.",sSrc:"The wind blows strongly today. Hold on to your hat!"},
{type:"story",speaker:"verumius",mood:"content",art:"de-ber-gendarmenmarkt-snow-falling",trg:"Es ist kalt und windig, aber der warme Glühwein hilft. Ich lerne jetzt Wetterwörter!",src:"It is cold and windy, but the warm mulled wine helps. I am learning weather words now!"}
]},

{id:"deu_r11l7",title:"Beschreibungen am Markt",icon:"🎨",xp:10,board:true,steps:[
{type:"intro",title:"Beschreibungen am Markt",desc:"Describe what you see at the Christmas market. Colors, sizes, people, and traditions.",goals:["Learn 10 descriptive adjectives","Learn 7 nouns for people, objects, and traditions","Use trotz + genitive to say despite"]},

{type:"teach",trg:"dunkel",src:"dark",pos:"adj",gender:null,phonetic:"dunkel",example:"A: Es wird schon um vier Uhr dunkel.\nB: Ja, typisch für Dezember in Deutschland.",exampleSrc:"A: It already gets dark at four o'clock.\nB: Yes, typical for December in Germany.",note:"Opposite: hell (bright). Die Dunkelheit = darkness (noun).",funFact:"In northern Germany in December, it is already dark around 4 PM. Short winter days make Christmas market lights feel even more magical."},
{type:"teach",trg:"bunt",src:"colorful",pos:"adj",gender:null,phonetic:"bunt",example:"A: Schau mal, die bunten Lichter!\nB: Der Weihnachtsmarkt sieht toll aus.",exampleSrc:"A: Look, the colorful lights!\nB: The Christmas market looks great.",note:"Bunt = many colors together. Kunterbunt = very colorful, higgledy-piggledy.",funFact:"'Bunter Abend' is a German expression for an evening of varied entertainment. The variety makes it 'bunt' (colorful)."},
{type:"teach",trg:"dick",src:"thick/fat",pos:"adj",gender:null,phonetic:"dik",example:"A: Ich brauche einen dicken Schal.\nB: Ja, am besten Wolle.",exampleSrc:"A: I need a thick scarf.\nB: Yes, wool is best.",note:"Dick = thick (for objects), fat (for people). Watch the context.",funFact:"'Dicke Freunde' means very close friends, not that they are overweight. The word describes closeness, not body type."},
{type:"teach",trg:"dünn",src:"thin",pos:"adj",gender:null,phonetic:"dünn",example:"A: Die Jacke ist zu dünn für Dezember.\nB: Du brauchst einen Wintermantel.",exampleSrc:"A: The jacket is too thin for December.\nB: You need a winter coat.",note:"Opposite of dick. Used for clothing, paper, and people.",funFact:"'Dünnhäutig' (thin-skinned) means sensitive in German, just as in English. The metaphor crosses language borders perfectly."},
{type:"fb",s:"Die Jacke ist zu {1} für den Winter. Du brauchst einen Mantel.",a:"dünn",opts:["dünn","dick","bunt","dunkel"],hint:"The opposite of thick. Not enough fabric to stay warm.",sSrc:"The jacket is too thin for winter. You need a coat."},
{type:"mc",q:"Welches Adjektiv beschreibt viele verschiedene Farben zusammen?",opts:["dunkel","bunt","dünn","dick"],ans:"bunt",hint:"Think of a rainbow or colorful Christmas lights."},
{type:"teach",trg:"eng",src:"tight/narrow",pos:"adj",gender:null,phonetic:"eng",example:"A: Die Gassen auf dem Markt sind eng.\nB: Ja, aber das macht es gemütlich.",exampleSrc:"A: The lanes at the market are narrow.\nB: Yes, but it makes it cozy.",note:"Eng = spatially narrow OR clothing that is too small.",funFact:"An 'enge Beziehung' (close relationship) is positive and means an intimate, trusting bond. The tightness implies closeness, not restriction."},
{type:"teach",trg:"modern",src:"modern",pos:"adj",gender:null,phonetic:"modärn",example:"A: Der neue Weihnachtsmarkt ist sehr modern.\nB: Ich mag die traditionellen Märkte lieber.",exampleSrc:"A: The new Christmas market is very modern.\nB: I prefer the traditional markets.",note:"Cognate. Stressed on the second syllable: moˈdern.",funFact:"Many Germans prefer 'traditionell' (traditional) over 'modern' when it comes to Christmas markets. Rustic wooden stalls beat steel-and-glass designs."},
{type:"teach",trg:"früh",src:"early",pos:"adj",gender:null,phonetic:"frü",example:"A: Wir müssen früh losgehen.\nB: Warum? Wann öffnet der Markt?\nA: Um elf, aber es wird schnell voll.",exampleSrc:"A: We have to leave early.\nB: Why? When does the market open?\nA: At eleven, but it gets crowded quickly.",note:"Opposite: spät (late). Früher = earlier / in the past.",funFact:"'Der frühe Vogel fängt den Wurm' is the German equivalent of 'the early bird catches the worm.' Same idea, same bird, different language."},
{type:"teach",trg:"einzeln",src:"individual/single",pos:"adj",gender:null,phonetic:"aintseln",example:"A: Kann ich einzelne Pralinen kaufen?\nB: Ja, fünfzig Cent pro Stück.",exampleSrc:"A: Can I buy individual chocolates?\nB: Yes, fifty cents each.",note:"Also: ein einzelner Mensch = a single person.",funFact:"'Einzelkind' (only child) is a neutral word in German, not negative. No connotations of loneliness are attached."},
{type:"fb",s:"Die Gassen auf dem Markt sind sehr {1}. Wir müssen hintereinander gehen.",a:"eng",opts:["eng","modern","früh","einzeln"],hint:"Not enough space to walk side by side. The alley is narrow.",sSrc:"The alleys at the market are very narrow. We have to walk in single file."},
{type:"teach",trg:"fleißig",src:"hardworking",pos:"adj",gender:null,phonetic:"flaißich",example:"A: Die Verkäufer auf dem Markt sind sehr fleißig.\nB: Ja, sie arbeiten von morgens bis abends.",exampleSrc:"A: The vendors at the market are very hardworking.\nB: Yes, they work from morning to evening.",note:"A classic German compliment. Fleiß = diligence (noun).",funFact:"'Fleiß' is one of the classic German virtues alongside Pünktlichkeit (punctuality) and Ordnung (orderliness). Hard work is deeply valued in German culture."},
{type:"teach",trg:"typisch",src:"typical",pos:"adj",gender:null,phonetic:"tüpisch",example:"A: Glühwein und Lebkuchen auf dem Markt.\nB: Das ist typisch deutsch!",exampleSrc:"A: Mulled wine and gingerbread at the market.\nB: That's typically German!",note:"Cognate. Typisch + für: typisch für Deutschland (typical for Germany).",funFact:"'Typisch!' as an exclamation often means 'that was to be expected.' Slightly exasperated. If Verumius is late again, Hildi will say 'Typisch.'"},
{type:"mc",q:"Wie ist das Gegenteil von 'dick'?",opts:["dünn","eng","bunt","dunkel"],ans:"dünn",hint:"These two adjectives describe opposing body types or thicknesses."},
{type:"fb",s:"Die {1} Lichter auf dem Weihnachtsmarkt sind wunderschön.",a:["bunten"],opts:["bunten","dunklen","engen","frühen"],hint:"The colorful lights are beautiful. Plural adjective with definite article.",sSrc:"The colorful lights at the Christmas market are beautiful."},
{type:"match",pairs:[{trg:"dunkel",src:"dark"},{trg:"modern",src:"modern"},{trg:"fleißig",src:"hardworking"},{trg:"einzeln",src:"individual"}]},
{type:"mc",q:"What does 'dunkel' mean?",opts:["colorful","dark","modern","early"],ans:"dark",hint:"The opposite of hell (bright). Used for December days and somber tones."},
{type:"mc",q:"Which adjective describes a jacket that is too thin for cold weather?",opts:["bunt","fleißig","dünn","einzeln"],ans:"dünn",hint:"The opposite of dick (thick). Not enough fabric to keep you warm."},
{type:"fb",s:"Die Verkäufer auf dem Markt sind sehr {1}. Sie arbeiten von morgens bis abends.",a:["fleißig"],opts:["fleißig","bunt","eng","typisch"],hint:"They work hard all day. A classic German virtue.",sSrc:"The vendors at the market are very hardworking. They work from morning to evening."},
{type:"mc",q:"'Das ist typisch für einen deutschen Weihnachtsmarkt.' Was bedeutet 'typisch'?",opts:["selten","fremd","charakteristisch","langweilig"],ans:"charakteristisch",hint:"Something that is representative and expected for this culture or place."}
]},

// ─── Lesson: Menschen und Dinge am Markt ───
{id:"deu_r11l8",title:"Menschen und Dinge am Markt",icon:"🎄",xp:15,board:true,steps:[
{type:"intro",title:"Menschen und Dinge am Markt",desc:"Meet the people and discover the things at the Weihnachtsmarkt: grandchildren, ladies, candles, fog, and Christmas songs. Plus the preposition trotz and the noun Fähigkeit.",goals:["Learn nouns for people, objects, and weather at the market","Use trotz (despite) with genitive","Practice adjective endings in context"]},
{type:"teach",trg:"der Enkel",src:"the grandson / grandchild",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Enkel.\nFeminine: die Enkelin (granddaughter). Plural: die Enkelinnen.",example:"A: Wie viele Enkel hast du, Heinrich?\nB: Drei Enkel! Hildi, Thomas und die kleine Lena.\nA: Hildi ist deine Enkelin?\nB: Ja, meine älteste Enkelin.",exampleSrc:"A: How many grandchildren do you have, Heinrich?\nB: Three grandchildren! Hildi, Thomas, and little Lena.\nA: Hildi is your granddaughter?\nB: Yes, my oldest granddaughter.",funFact:"In Germany, grandparents often live close to their grandchildren. The word 'Enkel' comes from Old High German 'eninchili' meaning 'little ancestor.' Grandchildren were seen as small versions of their grandparents."},
{type:"teach",trg:"die Dame",src:"the lady",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Damen. Polite term for a woman. Also the queen in chess.",example:"A: Wer ist diese Dame am Eingang?\nB: Das ist Hildi. Sie kennt jeden auf dem Markt.\nA: Sie sieht sehr elegant aus.\nB: Ja, Hildi ist immer elegant.",exampleSrc:"A: Who is that lady at the entrance?\nB: That is Hildi. She knows everyone at the market.\nA: She looks very elegant.\nB: Yes, Hildi is always elegant.",funFact:"'Dame' comes from Latin 'domina' (mistress, lady of the house). The same root gives French 'Madame' and English 'dam.' In German chess, the most powerful piece is 'die Dame.' One word, enormous range."},
{type:"teach",trg:"das Feuer",src:"the fire",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Feuer.\nRelated: Feuerwehr (fire department), Feuerzeug (lighter).",example:"A: Schau, ein Feuer auf dem Markt!\nB: Das ist eine Feuerschale. Zum Wärmen.\nA: Stell dich ans Feuer, es ist warm.\nB: Gute Idee, meine Hände sind eiskalt.",exampleSrc:"A: Look, a fire at the market!\nB: That is a fire bowl. For warming up.\nA: Stand by the fire, it is warm.\nB: Good idea, my hands are ice cold.",funFact:"At German Christmas markets, Feuerschalen (fire bowls) are gathering spots where strangers warm their hands and chat. The Feuerwehr (fire department) literally means 'fire defense.' Feuerzeug (lighter) means 'fire thing.'"},
{type:"teach",trg:"die Decke",src:"the blanket / ceiling",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Decken.\nTwo meanings: (1) blanket/cover, (2) ceiling.",example:"A: Mir ist kalt.\nB: Hier, nimm eine Decke!\nA: Danke, die Decke ist so weich.\nB: Ja, das ist reine Wolle.",exampleSrc:"A: I am cold.\nB: Here, take a blanket!\nA: Thanks, the blanket is so soft.\nB: Yes, that is pure wool.",funFact:"'Decke' means both 'blanket' and 'ceiling.' 'Mir fällt die Decke auf den Kopf' (the ceiling falls on my head) is an idiom meaning 'I am going stir-crazy' from being indoors too long. 'Bettdecke' specifically means the bed blanket."},
{type:"mc",q:"Heinrich hat drei ___: Hildi, Thomas und Lena.",opts:["Damen","Enkel","Feuer","Decken"],ans:"Enkel",hint:"The children of his children. A masculine noun for grandchildren."},
{type:"fb",s:"Mir ist kalt. Gib mir bitte eine {1}!",a:"Decke",opts:["Decke","Dame","Feuer","Nebel"],hint:"Something soft and warm you wrap yourself in.",sSrc:"I am cold. Please give me a blanket!"},
{type:"teach",trg:"der Nebel",src:"the fog / mist",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Nebel.\nAdjective: nebelig (foggy).",example:"A: Ich sehe den Weihnachtsmarkt nicht.\nB: Der Nebel ist heute sehr dicht.\nA: Kann man bei Nebel laufen?\nB: Ja, aber langsam und vorsichtig.",exampleSrc:"A: I cannot see the Christmas market.\nB: The fog is very dense today.\nA: Can you walk in the fog?\nB: Yes, but slowly and carefully.",funFact:"German November is famous for 'Novembernebel' (November fog). In river valleys like the Rhine, fog can last for days. The word 'Nebel' is related to Latin 'nebula' (cloud). Astronomy borrowed it back as 'nebula.'"},
{type:"teach",trg:"das Weihnachtslied",src:"the Christmas carol",pos:"noun",gender:"n",note:"Neuter noun. Compound: Weihnacht (Christmas) + Lied (song).\nPlural: die Weihnachtslieder.",example:"A: Kennst du ein deutsches Weihnachtslied?\nB: Ja! 'Stille Nacht, heilige Nacht.'\nA: Das ist ein typisches deutsches Weihnachtslied?\nB: Es kommt eigentlich aus Österreich!",exampleSrc:"A: Do you know a German Christmas carol?\nB: Yes! 'Silent Night, Holy Night.'\nA: Is that a typical German Christmas carol?\nB: It actually comes from Austria!",funFact:"'Stille Nacht' was first performed in 1818 in a church in Austria. 'O Tannenbaum' (O Christmas Tree) is probably the most famous German Weihnachtslied worldwide. German Weihnachtslieder are often played by live brass bands at Christmas markets."},
{type:"teach",trg:"die Fähigkeit",src:"the ability / skill",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Fähigkeiten.\nFrom 'fähig' (capable) + '-keit' (noun suffix).",example:"A: Verumius hat die Fähigkeit, schnell zu lernen.\nB: Ja, sein Deutsch wird jeden Tag besser.\nA: Sprachen lernen ist eine wichtige Fähigkeit.",exampleSrc:"A: Verumius has the ability to learn quickly.\nB: Yes, his German gets better every day.\nA: Learning languages is an important ability.",funFact:"The suffix '-keit' turns adjectives into nouns: fähig to Fähigkeit, möglich to Möglichkeit, freundlich to Freundlichkeit. Once you see this pattern, you unlock hundreds of abstract nouns in German."},
{type:"teach",trg:"trotz",src:"despite / in spite of",pos:"prep",gender:null,note:"Preposition. Takes the GENITIVE case.\ntrotz + genitive: trotz des Regens = despite the rain.",example:"A: Trotz des Schnees gehen wir auf den Markt.\nB: Natürlich! Ein bisschen Schnee stoppt uns nicht.\nA: Trotz der Kälte trinken alle Glühwein draußen.",exampleSrc:"A: Despite the snow, we are going to the market.\nB: Of course! A little snow does not stop us.\nA: Despite the cold, everyone drinks mulled wine outside.",funFact:"'Trotz' takes the genitive, which makes it a favorite word for testing German grammar. 'Trotzdem' (nevertheless) is the adverb form and extremely common in everyday speech. 'Es regnet? Ich gehe trotzdem!' (It is raining? I am going anyway!)"},
{type:"fb",s:"Im Dezember wird es in Deutschland sehr {1}.",a:"dunkel",opts:["dunkel","sonnig","heiß","bunt"],hint:"The sun sets early in winter. Not bright, not colorful.",sSrc:"In December it gets very dark in Germany."},
{type:"mc",q:"'Die bunten Lichter auf dem Weihnachtsmarkt.' Was bedeutet 'bunt'?",opts:["colorful","bright","dark","single"],ans:"colorful",hint:"Think of many different colors together. A rainbow is bunt."},
{type:"fb",s:"Der Schal ist zu {1} für den Winter. Ich brauche einen dickeren.",a:"dünn",opts:["dünn","eng","modern","früh"],hint:"The opposite of dick. Not enough fabric for the cold.",sSrc:"The scarf is too thin for winter. I need a thicker one."},
{type:"fb",s:"Ich brauche einen {1} Schal aus Wolle. Dünne Schals helfen nicht.",a:"dicken",opts:["dicken","engen","modernen","einzelnen"],hint:"The opposite of thin. You need a substantial scarf for warmth.",sSrc:"I need a thick scarf made of wool. Thin scarves do not help."},
{type:"mc",q:"'Die fleißigen Verkäufer arbeiten den ganzen Tag.' Was bedeutet 'fleißig'?",opts:["hardworking","lazy","tired","typical"],ans:"hardworking",hint:"These vendors work from morning to evening. Which word describes their dedication?"},
{type:"fb",s:"Das ist {1} für einen deutschen Weihnachtsmarkt: Glühwein, Bratwurst und Lebkuchen.",a:"typisch",opts:["typisch","einzeln","modern","eng"],hint:"It is normal and expected for Germany. Which adjective means that?",sSrc:"That is typical for a German Christmas market: mulled wine, bratwurst and gingerbread."},
{type:"mc",q:"Verumius will um 9 Uhr auf den Markt. Hildi sagt: 'Das ist zu ___! Der Markt öffnet erst um 11.'",opts:["spät","dunkel","früh","kühl"],ans:"früh",hint:"9 AM is before opening time at 11 AM. Too early, not too late."},
{type:"fb",s:"Die Gasse zum Weihnachtsmarkt ist sehr {1}. Wir müssen hintereinander gehen.",a:"eng",opts:["eng","dick","bunt","warm"],hint:"Not enough space to walk side by side. The alley is too narrow.",sSrc:"The alley to the Christmas market is very narrow. We have to walk in single file."},
{type:"mc",q:"Hildi kauft eine Praline. Sie will keine ganze Schachtel, nur eine ___.",opts:["dicke","einzelne","frühe","dunkle"],ans:"einzelne",hint:"Only one piece, not the whole box. Which adjective means individual or single?"},
{type:"mc",q:"Heinrich stellt Verumius vor: 'Das ist die ___, die den besten Glühwein macht.'",opts:["der Enkel","die Dame","das Feuer","die Decke"],ans:"die Dame",hint:"A polite word for a woman. Feminine noun."},
{type:"fb",s:"Es ist kalt. Stell dich ans {1}, dann wird dir warm!",a:"Feuer",opts:["Feuer","Nebel","Decke","Enkel"],hint:"Flames that give off heat. A fire bowl at the Christmas market.",sSrc:"It is cold. Stand by the fire, then you will get warm!"},
{type:"mc",q:"Mir ist kalt auf der Bank. Heinrich gibt mir eine warme ___.",opts:["Decke","Dame","Fähigkeit","Enkel"],ans:"Decke",hint:"Something soft you wrap yourself in when cold. A blanket."},
{type:"fb",s:"Heinrich hat drei {1}: Hildi, Thomas und Lena.",a:"Enkel",opts:["Enkel","Damen","Nebel","Feuer"],hint:"The children of his children. What is the word for grandchildren?",sSrc:"Heinrich has three grandchildren: Hildi, Thomas, and Lena."},
{type:"mc",q:"Auf dem Markt singt ein Chor ein schönes ___.",opts:["Weihnachtslied","Fähigkeit","Nebel","Decke"],ans:"Weihnachtslied",hint:"A song that is sung at Christmas. A carol."},
{type:"fb",s:"Sprachen lernen ist eine wichtige {1}.",a:"Fähigkeit",opts:["Fähigkeit","Decke","Dame","Nebel"],hint:"An ability or skill. A feminine noun ending in -keit.",sSrc:"Learning languages is an important ability."},
{type:"fb",s:"{1} des Schnees gehen wir auf den Weihnachtsmarkt.",a:"Trotz",opts:["Trotz","Wegen","Ohne","Nach"],hint:"A preposition meaning despite. Takes the genitive case.",sSrc:"Despite the snow, we are going to the Christmas market."},
{type:"drag_fill",s:"Der {1} Markt gefällt mir nicht. Ich mag die {2} Weihnachtsmärkte mit {3} Holzbuden.",blanks:{"1":"moderne","2":"traditionellen","3":"bunten"},pool:["moderne","traditionellen","bunten","einzelnen","dunklen"],hint:"New vs. old, and the stalls have many colors. Three adjectives with correct endings.",sSrc:"The modern market does not appeal to me. I prefer the traditional Christmas markets with colourful wooden stalls."},
{type:"match",pairs:[{trg:"der Enkel",src:"the grandchild"},{trg:"die Dame",src:"the lady"},{trg:"das Feuer",src:"the fire"},{trg:"die Decke",src:"the blanket"},{trg:"das Weihnachtslied",src:"the Christmas carol"}]},

{type:"story",speaker:"verumius",mood:"amused",art:"de-ber-gendarmenmarkt-snow-falling",trg:"Knuspriger Schnee. Ich schreibe mir das auf. Das brauche ich für die Prüfung.",src:"Crunchy snow. I am writing that down. I will need it for the exam."}
]},

{id:"deu_r11l9",title:"Glühwein",icon:"\ud83c\udf77",xp:20,board:true,steps:[
{type:"intro",title:"Glühwein",desc:"Three cups of Glühwein, steam rising, fairy lights reflected in the wine. Heinrich tells stories, Hildi rolls her eyes fondly. Verumius is warm and settled.",goals:["Learn 8 new adjectives and nouns","Practice adjective declension in all three cases","Review temporal prepositions, possessives, and Konjunktiv II"]},

{type:"story",speaker:"narrator",mood:"warm-climactic",art:"de-ber-gluehwein-scene",trg:"Drei Tassen Glühwein auf dem Holztisch. Dampf steigt in die kalte Nachtluft. Die Lichterketten spiegeln sich im Wein. Heinrich, Hildi und Verumius sitzen eng zusammen.",src:"Three cups of mulled wine on the wooden table. Steam rises into the cold night air. The fairy lights reflect in the wine. Heinrich, Hildi, and Verumius sit close together."},
{type:"story",speaker:"opa",mood:"ceremonial",art:"de-ber-gluehwein-toast",trg:"Heinrich hebt seine Tasse. 'Auf den jungen Mann, der unsere Sprache lernt. Auf den Schnee. Und auf frische Brötchen am Morgen.'",src:"Heinrich raises his cup. 'To the young man who is learning our language. To the snow. And to fresh bread rolls in the morning.'"},
{type:"story",speaker:"hildi",mood:"tender",art:"de-ber-gluehwein-scene",trg:"Auf uns drei.",src:"To the three of us."},
{type:"story",speaker:"narrator",mood:"profound",art:"de-ber-gluehwein-close",trg:"Sie trinken. Der Glühwein ist heiß, süß und voller Zimt. Aber das ist nicht, was Verumius wärmt. Seit Wochen lernt er Wörter. Heute Abend versteht er zum ersten Mal, warum.",src:"They drink. The mulled wine is hot, sweet, and full of cinnamon. But that is not what warms Verumius. For weeks he has been learning words. Tonight, for the first time, he understands why."},
{type:"teach",trg:"das Gewitter",
  pos:"noun",
  gender:"n",src:"thunderstorm",example:"A: Kommt heute Abend ein Gewitter?\nB: Nein, der Himmel ist klar. Perfekt für den Weihnachtsmarkt!",exampleSrc:"A: Is there a thunderstorm coming tonight?\nB: No, the sky is clear. Perfect for the Christmas market!",note:"das Gewitter (neuter). Despite der in some dialects, standard German uses das.",funFact:"German Christmas markets stay open even in light rain. Only a real Gewitter closes the stalls."},
{type:"teach",trg:"tief",
  pos:"adj",
  gender:null,src:"deep",example:"A: Der Glühwein hat einen tiefen Geschmack.\nB: Ja, mit Zimt und Nelken. Sehr lecker!",exampleSrc:"A: The mulled wine has a deep flavor.\nB: Yes, with cinnamon and cloves. Very tasty!",note:"tief: deep, low, profound. Opposite of hoch (high).",funFact:"Germans say 'tief in der Nacht' (deep in the night) for the late hours when Christmas markets finally close."},
{type:"teach",trg:"reich",
  pos:"adj",
  gender:null,src:"rich",example:"A: Heinrich kennt so viele reiche Geschichten!\nB: Ja, er hat ein reiches Leben gef\u00fchrt.",exampleSrc:"A: Heinrich knows so many rich stories!\nB: Yes, he has led a rich life.",note:"reich: rich (money or experience). Ein reiches Land, eine reiche Geschichte.",funFact:"The word 'Reich' originally just meant 'realm' or 'kingdom.' Frankreich (France) literally means 'realm of the Franks.'"},
{type:"teach",trg:"sterben",src:"to die",pos:"verb",gender:null,note:"Irregular strong verb: ich sterbe, du stirbst, er stirbt. Perfekt with sein: ist gestorben.",example:"A: Sein Gro\u00dfvater ist letztes Jahr gestorben.\nB: Das tut mir leid. War er alt?\nA: Ja, 91 Jahre. Er hat ein reiches Leben gef\u00fchrt.\nB: Das ist das Sch\u00f6nste.",exampleSrc:"A: His grandfather died last year.\nB: I am sorry. Was he old?\nA: Yes, 91 years. He led a rich life.\nB: That is the most beautiful thing.",funFact:"'Sterben' forms its Perfekt with sein because it describes a change of state. 'Er ist gestorben' = he has died. Germans often use softer phrases: 'Er ist von uns gegangen' (he has left us) or 'Er ist eingeschlafen' (he has fallen asleep) in formal speech."},
{type:"teach",trg:"arm",
  pos:"adj",
  gender:null,src:"poor",example:"A: Als Kind war Heinrich arm.\nB: Aber jetzt ist er reich an Freunden.",exampleSrc:"A: As a child, Heinrich was poor.\nB: But now he is rich in friends.",note:"arm: poor. Opposite of reich. Also: der Arm (noun) = the arm (body part).",funFact:"The phrase 'arm aber gl\u00fccklich' (poor but happy) is a common German saying, especially around Christmas."},
{type:"mc",q:"Was ist das Gegenteil von 'reich'?",opts:["tief","froh","arm","bequem"],ans:"arm",hint:"When you have very little money or possessions."},
{type:"fb",s:"Der Glühwein hat einen {1} Geschmack mit Zimt.",a:"tiefen",opts:["tiefen","reichen","armen","frohen"],hint:"Accusative masculine: einen ___en. Describes depth of flavor.",sSrc:"The mulled wine has a deep taste with cinnamon."},
{type:"teach",trg:"froh",src:"glad / happy",pos:"adj",gender:null,note:"Adjective. 'Ich bin froh' = I am glad. Slightly less intense than 'gl\u00fccklich' (happy).",example:"A: Ich bin froh, dass der Markt noch offen ist.\nB: Ich auch! Ich brauche noch einen Gl\u00fchwein.\nA: Das macht mich auch froh.\nB: Frohe Weihnachten!",exampleSrc:"A: I am glad the market is still open.\nB: Me too! I still need a mulled wine.\nA: That makes me happy too.\nB: Merry Christmas!",funFact:"'Frohe Weihnachten!' literally means 'Joyful Christmas!' The same root appears in 'Fr\u00f6hlichkeit' (cheerfulness). 'Frohlocken' (to rejoice) is older and more poetic, but 'froh sein' is everyday German."},
{type:"teach",trg:"bequem",
  pos:"adj",
  gender:null,src:"comfortable",example:"A: Ist dein Platz bequem?\nB: Ja, sehr! Und der Glühwein wärmt meine Hände.",exampleSrc:"A: Is your seat comfortable?\nB: Yes, very! And the mulled wine warms my hands.",note:"bequem: comfortable (seats, shoes, life). For temperature comfort, use gemütlich.",funFact:"Germans distinguish bequem (physically comfortable) from gemütlich (cozy atmosphere). A Weihnachtsmarkt is gemütlich, a chair is bequem."},
{type:"teach",trg:"hässlich",
  pos:"adj",
  gender:null,src:"ugly",example:"A: Hildi findet Heinrichs Weihnachtspullover hässlich.\nB: Aber Heinrich trägt ihn trotzdem jeden Winter!",exampleSrc:"A: Hildi finds Heinrich's Christmas sweater ugly.\nB: But Heinrich wears it every winter anyway!",note:"hässlich: ugly. Strong word. For 'not pretty,' Germans often soften with nicht so schön.",funFact:"Ugly Christmas sweaters (hässliche Weihnachtspullover) are a growing trend in Germany, borrowed from American culture."},
{type:"teach",trg:"intelligent",
  pos:"adj",
  gender:null,src:"intelligent",example:"A: Verumius ist ein intelligenter Kerl.\nB: Stimmt! Er lernt so schnell Deutsch.",exampleSrc:"A: Verumius is an intelligent guy.\nB: True! He learns German so quickly.",note:"intelligent: same as English. Note the ending changes: ein intelligenter Mann, eine intelligente Frau.",funFact:"German borrows 'intelligent' from Latin via French. The native German equivalent is klug, which feels warmer and less academic."},
{type:"fb",s:"Ist dein Platz {1}? Ja, sehr! Der Glühwein wärmt die Hände.",a:"bequem",opts:["bequem","hässlich","intelligent","froh"],hint:"This adjective describes physical comfort, like a good chair.",sSrc:"Is your seat comfortable? Yes, very! The mulled wine warms the hands."},
{type:"teach",trg:"klug",
  pos:"adj",
  gender:null,src:"clever, smart",example:"A: Das war eine kluge Entscheidung, hierher zu kommen.\nB: Ja, der Glühwein allein war es wert!",exampleSrc:"A: That was a clever decision to come here.\nB: Yes, the mulled wine alone was worth it!",note:"klug: clever, smart, wise. More everyday than intelligent. Ein kluger Kopf = a smart cookie.",funFact:"The Brothers Grimm used 'klug' constantly in their fairy tales. Das kluge Gretel, Die kluge Else. Cleverness was the ultimate survival trait."},
{type:"tip",title:"Glühwein und Freundschaft",text:"Heinrich hebt seine Tasse: 'Auf uns drei!' Hildi lächelt. Verumius spürt etwas Warmes, und es ist nicht nur der Glühwein. Er hat eine Familie gefunden, auf seine eigene Art.\n\nTonight we review everything from this unit: adjective endings across all three cases, temporal prepositions, possessives, and Konjunktiv II. The Glühwein scene brings it all together."},
{type:"mc",q:"Heinrich erzählt eine ___ Geschichte. (reich, nominative feminine)",opts:["reicher","reiches","reiche","reichen"],ans:"reiche",hint:"Feminine nominative: eine ___e Geschichte."},
{type:"fb",s:"Der Glühwein hat einen {1} Geschmack.",a:"tiefen",opts:["tiefen","tiefer","tiefes","tiefe"],hint:"Accusative masculine: einen ___en.",sSrc:"The mulled wine has a deep taste."},
{type:"mc",q:"Hildi sitzt auf einem ___ Stuhl. (bequem, dative masculine)",opts:["bequemer","bequemes","bequem","bequemen"],ans:"bequemen",hint:"Dative masculine after auf (location): einem ___en."},
{type:"drag_fill",s:"Heinrich war {1} Kind ein {2} Junge, aber er hatte {3} Freunde.",blanks:{"1":"als","2":"armer","3":"kluge"},pool:["als","armer","kluge","reiches","während","hässlicher"],hint:"Temporal prep + nom masc adj + acc plural adj.",sSrc:"Heinrich was as a child a poor boy, but he had clever friends."},
{type:"fb",s:"Wenn ich reich {1}, würde ich jeden Tag Glühwein trinken.",a:"wäre",opts:["wäre","bin","war","sei"],hint:"Konjunktiv II of sein for unreal wishes.",sSrc:"If I were rich, I would drink mulled wine every day."},
{type:"mc",q:"Das ist ___ Pullover! Niemand will ihn tragen. (nominative masculine, ein-word)",opts:["ein hässlicher","einen hässlichen","einem hässlichem","einer hässlicher"],ans:"ein hässlicher",hint:"Nominative masculine with the indefinite article: ___ ___er."},
{type:"drag_fill",s:"Verumius trinkt {1} Glühwein mit {2} klugen Freunden {3} dem Weihnachtsmarkt.",blanks:{"1":"seinen","2":"seinen","3":"auf"},pool:["seinen","seinen","auf","sein","seine","in"],hint:"Possessive accusative + possessive dative + location preposition.",sSrc:"Verumius drinks his mulled wine with his clever friends at the Christmas market."},
{type:"fb",s:"Wenn das Wetter {1} wäre, könnten wir nicht draußen sitzen.",a:"hässlich",opts:["hässlich","hässliches","hässlichen","hässlicher"],hint:"Predicate adjective after sein: no ending needed.",sSrc:"If the weather were ugly, we would not be able to sit outside."},
{type:"mc",q:"Heinrich hat eine ___ Stimme. Er erzählt gern Geschichten. (tief, accusative feminine)",opts:["tiefer","tiefe","tiefes","tiefen"],ans:"tiefe",hint:"Accusative feminine: eine ___e Stimme."},
{type:"drag_fill",s:"{1} des Gewitters {2} sie gemütlich {3} dem Markt.",blanks:{"1":"Trotz","2":"saßen","3":"auf"},pool:["Trotz","saßen","auf","Wegen","standen","in"],hint:"'Despite' + genitive, then past tense of sitzen + location.",sSrc:"Despite the thunderstorm they sat cosily at the market."},
{type:"match",pairs:[{trg:"tief",src:"deep"},{trg:"reich",src:"rich"},{trg:"arm",src:"poor"},{trg:"bequem",src:"comfortable"},{trg:"hässlich",src:"ugly"},{trg:"klug",src:"clever"}]},

{type:"story",speaker:"opa",mood:"warm-mischievous",art:"de-ber-gluehwein-scene",trg:"Noch ein Brötchen? Sie sind nicht mehr ganz frisch, aber die Butter in meiner Manteltasche ist noch gut.",src:"Another bread roll? They are not quite fresh anymore, but the butter in my coat pocket is still good."},
{type:"story",speaker:"verumius",mood:"belonging",art:"de-ber-gluehwein-bench",trg:"Verumius nimmt das Brötchen. Es schmeckt nach einem langen Tag, nach Zimt und nach Zuhause.",src:"Verumius takes the bread roll. It tastes of a long day, of cinnamon, and of home."}
]},

{id:"deu_r11l10",title:"Weihnachtsprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Weihnachtsprüfung",desc:"The Glühwein is gone, the lights are blinking, and Opa Heinrich is waiting for answers. Show what you learned at the Christmas market. No new words. Just you and the grammar.",goals:["Adjective declension in nominative, accusative, and dative","Possessive articles in all cases","Use temporal prepositions correctly","Konjunktiv II for wishes and hypotheticals"]},

{type:"mc",q:"'Der warme Glühwein schmeckt gut.' Warum endet das Adjektiv auf -e?",opts:["Nach bestimmtem Artikel im Nominativ: immer -e","Das Adjektiv zeigt das Genus mit -e","Warm ist unregelmäßig","Glühwein ist feminin"],ans:"Nach bestimmtem Artikel im Nominativ: immer -e",hint:"After a definite article in the subject position, adjective suffixes follow a simple pattern."},
{type:"fb",s:"Ein kalt{1} Wind weht über den Markt.",a:"er",opts:["er","e","es","en"],hint:"After 'ein' in nominative, what ending does the adjective need for a masculine noun?",sSrc:"A cold wind blows over the market."},
{type:"mc",q:"Hildi sagt: 'Ich trage meinen dicken Mantel.' Welcher Fall ist 'meinen dicken Mantel'?",opts:["Nominativ","Akkusativ","Dativ","Genitiv"],ans:"Akkusativ",hint:"Tragen takes a direct object. Think about what case marks that."},
{type:"drag_fill",s:"Heinrich schenkt {1} Enkelin {2} goldenen Ring.",blanks:{"1":"seiner","2":"einen"},pool:["seiner","seine","seinem","einen","ein","einem"],hint:"Schenken: dative (to whom?) + accusative (what?). Enkelin is feminine, Ring is masculine.",sSrc:"Heinrich gives his granddaughter a golden ring."},
{type:"fb",s:"Verumius trinkt {1} heißen Glühwein auf dem Markt.",a:"einen",opts:["einen","ein","einem","einer"],hint:"Glühwein is masculine. Direct object means accusative case.",sSrc:"Verumius drinks a hot mulled wine at the market."},
{type:"mc",q:"Welches Wort zeigt den Dativ in: 'Er sitzt mit ___ warmen Pullover am Feuer'?",opts:["einen","ein","einem","einer"],ans:"einem",hint:"'Mit' always governs one specific case. Look at the article form."},
{type:"drag_fill",s:"{1} dem Essen gehen wir {2} den bunten Weihnachtsmarkt.",blanks:{"1":"Nach","2":"auf"},pool:["Nach","Vor","Seit","auf","in","an"],hint:"First eat, then go. Which temporal preposition means 'after'? And which preposition with accusative for destination?",sSrc:"After the meal we go to the colourful Christmas market."},
{type:"fb",s:"{1} drei Wochen ist der Weihnachtsmarkt geöffnet.",a:"Seit",opts:["Seit","Vor","Nach","Bis"],hint:"The market opened three weeks ago and is still open now.",sSrc:"For three weeks the Christmas market has been open."},
{type:"mc",q:"'Wenn ich reich wäre, würde ich jeden Tag Torte essen.' Was drückt dieser Satz aus?",opts:["Eine echte Absicht für die Zukunft","Eine Erinnerung an die Vergangenheit","Einen hypothetischen Wunsch","Einen Befehl an eine andere Person"],ans:"Einen hypothetischen Wunsch",hint:"The speaker imagines something that is not real. Which grammatical mood fits?"},
{type:"fb",s:"Ich {1} gern eine Reise nach Wien machen.",a:"würde",opts:["würde","werde","wurde","wollte"],hint:"For polite hypothetical wishes, use Konjunktiv II of werden + infinitive.",sSrc:"I would like to take a trip to Vienna."},
{type:"drag_fill",s:"Hildi gibt {1} alten Mann {2} warme Decke {3} dem Fest.",blanks:{"1":"dem","2":"eine","3":"nach"},pool:["dem","den","der","eine","einen","einem","nach","vor","seit"],hint:"Dative recipient (masc.) + accusative object (fem.) + temporal preposition meaning 'after'.",sSrc:"Hildi gives the old man a warm blanket after the celebration."},
{type:"mc",q:"'In meinem bequemen Bett schlafe ich gut.' Welchen Fall regiert 'in' hier?",opts:["Akkusativ","Dativ","Nominativ","Genitiv"],ans:"Dativ",hint:"'In' with location (where something happens) takes a specific case. No movement involved."},
{type:"fb",s:"Die fleißig{1} Verkäufer arbeiten den ganzen Tag.",a:"en",opts:["en","e","er","es"],hint:"Nominative plural after 'die': weak declension applies.",sSrc:"The hardworking vendors work all day."},
{type:"drag_fill",s:"Heinrich erzählt von {1} Kindheit {2} dem Krieg.",blanks:{"1":"seiner","2":"vor"},pool:["seiner","seinem","seine","vor","nach","seit"],hint:"'Von' takes dative. Kindheit is feminine. And which temporal preposition means 'before'?",sSrc:"Heinrich tells of his childhood before the war."},
{type:"mc",q:"'Verumius hätte gern ein warmes Bett.' Was bedeutet 'hätte'?",opts:["has (present)","had (simple past)","would have","will have (future)"],ans:"would have",hint:"This is an irregular Konjunktiv II form derived from 'haben.'"},
{type:"fb",s:"Mit {1} neuen Mütze sieht Hildi toll aus.",a:"ihrer",opts:["ihrer","ihrem","ihren","ihre"],hint:"'Mit' takes dative. Mütze is feminine. What is the dative feminine possessive for 'her'?",sSrc:"With her new hat Hildi looks great."},
{type:"drag_fill",s:"Verumius {1} gern {2} roten Schal kaufen, aber er {3} nicht genug Geld.",blanks:{"1":"würde","2":"den","3":"hätte"},pool:["würde","wäre","den","dem","einen","hätte","könnte"],hint:"Konjunktiv II wish + accusative masculine definite + irregular Konjunktiv II of haben.",sSrc:"Verumius would like to buy the red scarf, but he did not have enough money."},
{type:"mc",q:"'Während des Gewitters bleiben alle in der warmen Hütte.' Was regiert 'während'?",opts:["Akkusativ","Dativ","Nominativ","Genitiv"],ans:"Genitiv",hint:"This temporal preposition is one of the few that governs a case you rarely see elsewhere."},
{type:"fb",s:"Das ist ein typisch{1} deutsches Weihnachtslied.",a:"es",opts:["es","er","e","en"],hint:"Lied is neuter. After 'ein' in nominative neuter, the adjective shows the gender.",sSrc:"That is a typical German Christmas carol."},
{type:"drag_fill",s:"{1} der Ferien {2} ich gern auf {3} schönen Markt gehen.",blanks:{"1":"Während","2":"würde","3":"den"},pool:["Während","Seit","Vor","würde","werde","wurde","den","dem","der"],hint:"Temporal prep + genitive, Konjunktiv II, accusative masculine (direction).",sSrc:"During the holidays I would like to go to the beautiful market."},
{type:"match",pairs:[{trg:"vor dem Essen",src:"before the meal"},{trg:"nach Weihnachten",src:"after Christmas"},{trg:"seit einer Woche",src:"for a week"},{trg:"während des Fests",src:"during the festival"},{trg:"bis Freitag",src:"until Friday"},{trg:"ab morgen",src:"starting tomorrow"}]},

{type:"mc",q:"'Wenn es nicht so kalt wäre, könnten wir draußen sitzen.' Was drückt 'könnten' aus?",opts:["Eine hypothetische Möglichkeit","Eine tatsächliche Fähigkeit im Alltag","Eine vergangene Fähigkeit aus der Jugend","Einen konkreten Zukunftsplan für morgen"],ans:"Eine hypothetische Möglichkeit",hint:"The whole sentence describes an unreal condition. The verb form matches."},
{type:"drag_fill",s:"Heinrich schenkt {1} Enkelin {2} bequemen Schal und erzählt von {3} Kindheit.",blanks:{"1":"seiner","2":"einen","3":"seiner"},pool:["seiner","seiner","einen","eine","seinem","ihren"],hint:"Dative fem. possessive (to whom?) + accusative masc. (what?) + dative fem. possessive after 'von.'",sSrc:"Heinrich gives his granddaughter a comfortable scarf and tells of his childhood."},
{type:"fb",s:"Wenn ich Deutsch perfekt sprechen {1}, wäre das wunderbar.",a:"könnte",opts:["könnte","kann","konnte","können"],hint:"Irregular Konjunktiv II of 'können' for a hypothetical ability.",sSrc:"If I could speak German perfectly, that would be wonderful."},
{type:"match",pairs:[{trg:"der rote Schal",src:"the red scarf (nom.)"},{trg:"den roten Schal",src:"the red scarf (acc.)"},{trg:"dem roten Schal",src:"the red scarf (dat.)"},{trg:"ein roter Schal",src:"a red scarf (nom.)"},{trg:"einen roten Schal",src:"a red scarf (acc.)"},{trg:"einem roten Schal",src:"a red scarf (dat.)"}]}
]},

{id:"deu_r11l11",title:"Durch den Schnee",icon:"❄️",xp:15,board:true,steps:[
{type:"intro",title:"Durch den Schnee",desc:"Walking home through snowy Berlin after the Weihnachtsmarkt. Heinrich's bread in the bag, warmth in the heart.",goals:["Personality and character adjectives","Time expressions beyond today","Everyday verbs for learning"]},

{type:"story",speaker:"narrator",mood:"happy",art:"de-snowy-street",trg:"Schnee auf den Straßenlaternen. Schnee auf den parkenden Autos. Schnee auf Verumius' Schultern. In der Tasche: Heinrichs Brötchen. Im Herzen: Wärme. Er geht langsam nach Hause.",src:"Snow on the streetlamps. Snow on the parked cars. Snow on Verumius's shoulders. In the bag: Heinrich's bread rolls. In the heart: warmth. He walks slowly home."},
{type:"story",speaker:"narrator",mood:"quiet-content",art:"de-ber-snowy-street-door",trg:"An der Haustür dreht er sich um. Die Stadt ist still. Nur der Schnee fällt. Morgen wird er neue Wörter lernen. Aber heute Nacht reichen die alten.",src:"At the front door he turns around. The city is quiet. Only the snow falls. Tomorrow he will learn new words. But tonight, the old ones are enough."},
{type:"teach",trg:"egal",
  pos:"adj",
  gender:null,src:"doesn't matter / irrelevant",note:"Das ist mir egal = I don't care. Very common.",example:"A: Willst du Tee oder Kaffee?\nB: Das ist mir egal. Beides ist gut.\nA: Dann mache ich Tee.",exampleSrc:"A: Do you want tea or coffee?\nB: I don't care. Both are fine.\nA: Then I'll make tea.",funFact:"From Latin 'aequalis' (equal). If two things are equal, neither matters more."},
{type:"teach",trg:"freiwillig",
  pos:"adj",
  gender:null,src:"voluntary",note:"Frei (free) + willig (willing). Freiwillige Feuerwehr = volunteer fire dept.",example:"A: Ist die Teilnahme freiwillig?\nB: Ja, niemand muss kommen.\nA: Gut, dann komme ich gern!",exampleSrc:"A: Is participation voluntary?\nB: Yes, nobody has to come.\nA: Good, then I'll gladly come!",funFact:"Germany has 22,000 volunteer fire departments vs only 100 professional ones."},
{type:"teach",trg:"verschieden",
  pos:"adj",
  gender:null,src:"different / various",note:"Verschiedene Leute = various people.",example:"A: Die Glühweinsorten sind ganz verschieden.\nB: Ja, mit Orange, mit Kirsche, klassisch...",exampleSrc:"A: The varieties are quite different.\nB: Yes, with orange, cherry, classic...",funFact:"Literally means 'shifted apart.' Things shifted away from each other are different."},
{type:"mc",q:"'Das ist mir egal' means:",opts:["I don't care","I am feeling very sad","I disagree","I am hungry"],ans:"I don't care",hint:"Both options are equal to you. Neither matters more."},
{type:"teach",trg:"blöd",
  pos:"adj",
  gender:null,src:"stupid / annoying",note:"Colloquial. 'Das ist blöd' = That's annoying. Milder than dumm.",example:"A: Ich habe meinen Schlüssel vergessen.\nB: Das ist blöd! Hast du einen Ersatzschlüssel?",exampleSrc:"A: I forgot my key.\nB: That's annoying! Do you have a spare?",funFact:"Originally meant 'weak-sighted' in Old German. Now mostly means 'annoying.'"},
{type:"teach",trg:"dumm",
  pos:"adj",
  gender:null,src:"dumb / stupid",note:"Stronger than bl\u00f6d. Dumm wie Brot = dumb as bread.",example:"A: War das eine dumme Idee?\nB: Nein! Manchmal muss man Risiken eingehen.",exampleSrc:"A: Was that a stupid idea?\nB: No! Sometimes you have to take risks.",funFact:"'Dumm wie Brot' exists because bread just sits there doing nothing."},
{type:"teach",trg:"der Witz",src:"the joke",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Witze. 'Einen Witz machen' = to make a joke.",example:"A: Kennst du einen Witz?\nB: Ja! Was macht ein Nilpferd auf einem Weihnachtsmarkt?\nA: Keine Ahnung.\nB: Gl\u00fchwein trinken, was sonst!",exampleSrc:"A: Do you know a joke?\nB: Yes! What does a hippo do at a Christmas market?\nA: No idea.\nB: Drink mulled wine, what else!",funFact:"'Der Witz' can also mean 'wit' or 'the point of something': 'Das ist der Witz dabei!' = That is the whole point! Germans love wordplay and puns (Wortspiele), though they joke that German humor is 'no laughing matter.'"},
{type:"teach",trg:"faul",
  pos:"adj",
  gender:null,src:"lazy",note:"Also means 'rotten' (fauler Apfel). Context decides.",example:"A: Bist du heute faul?\nB: Ja! Ich bleibe auf dem Sofa.",exampleSrc:"A: Are you lazy today?\nB: Yes! I'm staying on the sofa.",funFact:"Faulenzen on Sundays is protected by Sonntagsruhe law in Germany."},
{type:"teach",trg:"streng",
  pos:"adj",
  gender:null,src:"strict",note:"Strenge Regeln = strict rules. Hildi ist streng aber fair.",example:"A: Ist dein Chef streng?\nB: Ja, aber er ist auch fair.",exampleSrc:"A: Is your boss strict?\nB: Yes, but he is also fair.",funFact:"Being streng in Germany is often positive: it means you have standards."},
{type:"fb",s:"Hildi ist {1}, aber sie hat ein großes Herz.",a:["streng"],opts:["streng","faul","dumm","egal"],hint:"She has strict rules, but she cares deeply underneath.",sSrc:"Hildi is strict, but she has a big heart."},
{type:"teach",trg:"deutlich",
  pos:"adj",
  gender:null,src:"clear / distinct",note:"Bitte sprechen Sie deutlich = Please speak clearly.",example:"A: Können Sie das deutlicher sagen?\nB: Natürlich. Ich wiederhole langsam.",exampleSrc:"A: Can you say that more clearly?\nB: Of course. I'll repeat slowly.",funFact:"Comes from 'deutsch' via 'diutisc' (of the people). Speaking clearly = speaking for the people."},
{type:"teach",trg:"eigen",
  pos:"adj",
  gender:null,src:"own",note:"Mein eigenes Zimmer = my own room.",example:"A: Hast du eine eigene Wohnung?\nB: Nein, nur ein eigenes Zimmer.",exampleSrc:"A: Do you have your own apartment?\nB: No, just my own room.",funFact:"Eigentum, Eigenschaft, eigenartig. 'Eigen' spawns dozens of compound words."},
{type:"mc",q:"'Sprechen Sie deutlich' asks someone to:",opts:["speak quietly","speak clearly","speak German","speak faster"],ans:"speak clearly",hint:"You want to understand every word. Clear and distinct."},
{type:"teach",trg:"damals",
  pos:"adv",
  gender:null,src:"back then / at that time",note:"Temporal adverb for the past. Damals war alles anders.",example:"A: Damals gab es kein Internet.\nB: Wirklich? Wie habt ihr kommuniziert?\nA: Mit Briefen!",exampleSrc:"A: Back then there was no internet.\nB: Really? How did you communicate?\nA: With letters!",funFact:"Heinrich says 'damals' constantly. For someone born in the 1930s, it covers a LOT of history."},
{type:"teach",trg:"übermorgen",
  pos:"adv",
  gender:null,src:"the day after tomorrow",note:"Über (beyond) + morgen (tomorrow). One word in German!",example:"A: Wann kommt das Paket?\nB: Übermorgen. Am Donnerstag.",exampleSrc:"A: When does the package arrive?\nB: Day after tomorrow. Thursday.",funFact:"German has übermorgen and vorgestern. English needs 3+ words for each."},
{type:"teach",trg:"vorgestern",
  pos:"adv",
  gender:null,src:"the day before yesterday",note:"Vor (before) + gestern (yesterday).",example:"A: Wann war das Konzert?\nB: Vorgestern. Am Dienstag.",exampleSrc:"A: When was the concert?\nB: Day before yesterday. Tuesday.",funFact:"Some dialects even have 'vorvorgestern' (3 days ago). Efficient!"},
{type:"teach",trg:"zeigen",
  pos:"verb",
  gender:null,src:"to show",note:"Regular: ich zeige, du zeigst. Zeig mal! = Show me!",example:"A: Kann ich dir etwas zeigen?\nB: Ja! Was ist es?\nA: Mein neues Bild!",exampleSrc:"A: Can I show you something?\nB: Yes! What is it?\nA: My new painting!",funFact:"Zeigefinger = index finger (literally: showing finger)."},
{type:"teach",trg:"üben",
  pos:"verb",
  gender:null,src:"to practice",note:"Regular: ich übe, du übst. Übung macht den Meister!",example:"A: Übst du jeden Tag Deutsch?\nB: Ja, mindestens eine Stunde.\nA: Übung macht den Meister!",exampleSrc:"A: Do you practice German every day?\nB: Yes, at least one hour.\nA: Practice makes perfect!",funFact:"Every German teacher says 'Übung macht den Meister.' The most-used learning proverb."},
{type:"teach",trg:"die Übung",
  pos:"noun",src:"the exercise / the practice",gender:"f",example:"A: Wie wird man besser?\nB: Nur durch Übung! Übung macht den Meister.\nA: Dann übe ich jeden Tag.",exampleSrc:"A: How do you get better?\nB: Only through practice! Practice makes perfect.\nA: Then I will practice every day.",note:"die Übung, feminine. Plural: die Übungen. From the verb üben (to practice).",funFact:"The proverb 'Übung macht den Meister' (practice makes the master) is used in every German classroom, sports club, and music lesson."},
{type:"fb",s:"{1} macht den Meister!",a:["Übung"],opts:["Übung","Ordnung","Bildung","Erfahrung"],hint:"Practice makes perfect. Which word means 'practice'?",sSrc:"Practice makes perfect!"},
{type:"teach",trg:"aussprechen",
  pos:"verb",
  gender:null,src:"to pronounce",note:"Separable: ich spreche aus. Wie spricht man das aus?",example:"A: Wie spricht man 'Eichhörnchen' aus?\nB: Das ist schwer! Aich-hörn-chen.",exampleSrc:"A: How do you pronounce 'Eichhörnchen'?\nB: That's hard! Aich-hörn-chen.",funFact:"'Eichhörnchen' (squirrel) is the word Germans use to test foreigners. Nobody gets it right first time."},
{type:"drag_fill",s:"{1} war alles anders. Aber {2} haben wir Internet und Handys.",blanks:{"1":"Damals","2":"heute"},pool:["Damals","heute","Morgen","Gestern","übermorgen","vorgestern"],hint:"Back then vs now. Past contrasted with present.",sSrc:"Back then everything was different. But today we have the internet and mobile phones."},
{type:"teach",trg:"blond",
  pos:"adj",
  gender:null,src:"blond / fair-haired",example:"A: Hildi ist blond, oder?\nB: Ja, sie hat blonde Haare.\nA: Und Verumius?",exampleSrc:"A: Hildi is blond, right?\nB: Yes, she has blond hair.\nA: And Verumius?",note:"blond: same word as English. Endings change: blonder Mann, blonde Frau, blondes Kind.",funFact:"Germany has one of the highest percentages of natural blonds in the world, especially in the north."},
{type:"teach",trg:"einmal",
  pos:"adv",
  gender:null,src:"once / one time",example:"A: Warst du schon einmal in Wien?\nB: Ja, einmal. Es war wunderschön.\nA: Ich möchte auch einmal dorthin.",exampleSrc:"A: Have you ever been to Vienna?\nB: Yes, once. It was wonderful.\nA: I would like to go there too.",note:"einmal = once. Zweimal = twice. Dreimal = three times. Also used in 'Es war einmal...' (Once upon a time).",funFact:"Every German fairy tale starts with 'Es war einmal...' (Once upon a time). The Brothers Grimm made this opening famous worldwide."},
{type:"teach",trg:"wurscht",
  pos:"adj",
  gender:null,src:"doesn't matter (colloquial)",example:"A: Willst du Pizza oder Pasta?\nB: Das ist mir wurscht!\nA: Na gut, dann Pizza.",exampleSrc:"A: Do you want pizza or pasta?\nB: I don't care!\nA: Alright, pizza then.",note:"Colloquial southern German variant of 'egal.' Very common in Bavaria and Austria. From Wurst (sausage).",funFact:"'Das ist mir Wurst' or 'wurscht' literally means 'that is sausage to me.' Nobody knows exactly why sausage means indifference, but it has been used since the 1800s."},
{type:"match",pairs:[{trg:"egal",src:"doesn't matter"},{trg:"streng",src:"strict"},{trg:"faul",src:"lazy"},{trg:"deutlich",src:"clear"},{trg:"damals",src:"back then"},{trg:"übermorgen",src:"day after tomorrow"},{trg:"üben",src:"to practice"},{trg:"zeigen",src:"to show"}]},

{type:"tip",title:"German Christmas Traditions",text:"Weihnachten starts December 24 (Heiligabend), not December 25.\n\n- Adventskranz: 4 candles, one lit each Sunday before Christmas\n- Adventskalender: 24 doors, one per day in December\n- Nikolaus (Dec 6): shoes by the door, filled with sweets\n- Heiligabend: family dinner, gifts, church\n- Weihnachtsgans: roast goose, the traditional Christmas meal\n- Stille Nacht: world's most famous carol, written in Austria 1818",deepDive:"The Weihnachtsmarkt tradition dates to the 14th century. Dresden's Striezelmarkt (1434) is the oldest. Every city has one. Many Germans visit 5-10 different markets each season."},
{type:"mc",q:"Walking through snow, Verumius feels:",opts:["cold and lonely walking in the dark","angry about the freezing cold weather","warm and content, like he belongs","worried about what tomorrow may bring"],ans:"warm and content, like he belongs",hint:"Bread from a friend in the bag. A glow from the market in the chest."}
]}



]};

export default UNIT_11;
